-- Schema for Domain: order | Business: Telecommunication | Version: v1_mvm
-- Generated on: 2026-05-08 08:31:45

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `telecommunication_ecm`.`order` COMMENT 'SSOT for end-to-end order management and fulfillment — new activations, upgrades, downgrades, disconnections, MNP port-in/port-out, and change-of-service requests. Orchestrates order decomposition, workflow coordination, and fulfillment across OSS/BSS systems via Oracle Communications Order and Service Management.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `telecommunication_ecm`.`order`.`fulfillment_order` (
    `fulfillment_order_id` BIGINT COMMENT 'Unique surrogate identifier for every end-to-end fulfillment order record in the telecommunications order management system. Primary key of this product; globally unique across all order types (new activation, upgrade, downgrade, disconnection, MNP port-in/port-out, change-of-service).',
    `address_id` BIGINT COMMENT 'Reference to the physical installation address for orders requiring field work (FTTH, GPON, CPE installation, fixed-line provisioning). Links to the address/location master in the Network or Customer domain. Null for mobile-only orders with no physical installation.',
    `audit_id` BIGINT COMMENT 'Foreign key linking to compliance.audit. Business justification: Regulatory and high-value orders (is_regulatory_order=true) are subject to compliance audits. Linking fulfillment_order to the audit record enables auditors to directly reference the order under revie',
    `bundle_id` BIGINT COMMENT 'Foreign key linking to product.bundle. Business justification: Bundle order fulfillment decomposition: when a Triple Play or converged bundle is ordered, the fulfillment order references the bundle to drive component decomposition into child order lines. Telecom ',
    `corporate_account_id` BIGINT COMMENT 'Foreign key linking to enterprise.corporate_account. Business justification: B2B order processing requires corporate account linkage for contract validation, billing consolidation, account-level SLA tracking, and enterprise customer lifecycle management. Core business relation',
    `customer_account_id` BIGINT COMMENT 'FK to customer.customer_account.customer_account_id — Every order must join to the customer who placed it. This is the most critical cross-domain join for order management, billing reconciliation, and customer service queries.',
    `dealer_id` BIGINT COMMENT 'Foreign key linking to partner.dealer. Business justification: Dealer-originated orders require direct dealer attribution for commission calculation, quota tracking, and dealer performance measurement - standard telecommunications indirect channel sales process.',
    `device_model_id` BIGINT COMMENT 'Foreign key linking to product.device_model. Business justification: Device order fulfillment: when a handset or CPE device is ordered, the fulfillment order must reference the specific device model for logistics, inventory allocation, and device provisioning workflows',
    `discount_scheme_id` BIGINT COMMENT 'Foreign key linking to enterprise.discount_scheme. Business justification: The enterprise discount scheme applied at order creation governs pricing across all order lines and charges. Order-level discount scheme reference enables revenue assurance, discount scheme utilizatio',
    `carrier_id` BIGINT COMMENT 'Foreign key linking to interconnect.carrier. Business justification: MNP donor carrier identification: fulfillment_order for port-in must reference the donor carrier for inter-operator coordination, settlement, and regulatory reporting. Role prefix donor_ distinguish',
    `enterprise_contract_id` BIGINT COMMENT 'Foreign key linking to enterprise.enterprise_contract. Business justification: Orders execute against master service agreements. Required for contract compliance validation, pricing verification, commitment tracking, penalty calculation, and regulatory reporting for government/e',
    `iot_deployment_id` BIGINT COMMENT 'Foreign key linking to enterprise.iot_deployment. Business justification: Fulfillment orders for IoT deployment activation, expansion, or decommissioning must reference the IoT deployment at order header level for deployment-level order tracking and project management repor',
    `managed_service_id` BIGINT COMMENT 'Foreign key linking to enterprise.managed_service. Business justification: Fulfillment orders are raised to provision, modify, or decommission managed services. Direct link enables managed service lifecycle order history, change management tracking, and managed service deliv',
    `mnp_compliance_id` BIGINT COMMENT 'Foreign key linking to compliance.mnp_compliance. Business justification: MNP porting orders (with mnp_donor_operator_code, porting_authorization_code) must be linked to their mnp_compliance record for regulatory SLA tracking, porting authorization verification, and regulat',
    `element_id` BIGINT COMMENT 'Foreign key linking to network.element. Business justification: Orders for broadband/fiber services require assignment to specific network elements (DSLAM, OLT, BRAS) during fulfillment. Critical for network resource allocation, capacity management, and provisioni',
    `offering_id` BIGINT COMMENT 'Foreign key linking to product.offering. Business justification: Orders must reference the marketed offering (not just technical product_spec) for campaign attribution, sales compensation, channel performance tracking, and marketing ROI analysis. Business-facing pr',
    `partner_id` BIGINT COMMENT 'Foreign key linking to partner.partner. Business justification: Orders placed through partner channels (MVNOs, dealers, retail partners) require partner attribution for commission calculation, revenue sharing settlement, and partner performance tracking - core tel',
    `quote_id` BIGINT COMMENT 'Foreign key linking to sales.quote. Business justification: Order-to-cash traceability: a fulfillment order is generated from an accepted quote. Telecom revenue assurance and billing teams require the fulfillment order to reference its originating quote to val',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Telco orders often fulfill regulatory obligations (lawful intercept provisioning, emergency service activation, accessibility mandates). Operations must track which regulation governs each order for c',
    `revenue_share_plan_id` BIGINT COMMENT 'Foreign key linking to partner.revenue_share_plan. Business justification: Partner and dealer-originated fulfillment orders are governed by a specific revenue share plan determining commission rates and settlement terms. Telecom operators link orders directly to the applicab',
    `sdwan_topology_id` BIGINT COMMENT 'Foreign key linking to enterprise.sdwan_topology. Business justification: Fulfillment orders for SD-WAN topology provisioning, site additions, or topology changes must reference the SD-WAN topology. Enables topology-level order history and multi-site rollout project trackin',
    `segment_id` BIGINT COMMENT 'Foreign key linking to enterprise.segment. Business justification: Enterprise segment drives order processing rules, credit check requirements, SLA tier assignment, and discount eligibility at order creation. Direct link enables segment-level order volume and revenue',
    `site_id` BIGINT COMMENT 'Foreign key linking to enterprise.site. Business justification: Enterprise orders target specific customer sites for service installation and provisioning. Essential for field dispatch coordination, site-level SLA management, and multi-location enterprise service ',
    `sla_contract_id` BIGINT COMMENT 'Foreign key linking to assurance.sla_contract. Business justification: Every fulfillment order is governed by an assurance SLA contract defining measurement rules, penalty clauses, and breach thresholds. Telecom SLA breach reporting and regulatory compliance require trac',
    `slice_id` BIGINT COMMENT 'Foreign key linking to network.slice. Business justification: 5G network slice orders (enterprise private slices, IoT dedicated slices) are tied to a specific network slice being provisioned or modified. Order management must reference the slice to orchestrate i',
    `spec_id` BIGINT COMMENT 'Reference to the product or service catalog item being ordered, upgraded, downgraded, or disconnected. Links to the product catalog master in the Product domain. Sourced from Netcracker OSS/BSS Product Catalog.',
    `transmission_link_id` BIGINT COMMENT 'Foreign key linking to network.transmission_link. Business justification: Enterprise leased-line and fixed broadband fulfillment orders are directly associated with the transmission link being activated or upgraded. Order management and provisioning orchestration require th',
    `actual_completion_timestamp` TIMESTAMP COMMENT 'The precise date and time when the fulfillment order was actually completed and all downstream provisioning tasks confirmed. Used to calculate actual fulfillment duration, SLA adherence, and MTTR reporting. Null until order reaches COMPLETED status. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `cancellation_timestamp` TIMESTAMP COMMENT 'The precise date and time when the fulfillment order was cancelled. Null for non-cancelled orders. Used for cancellation rate analytics, churn analysis, and order fallout reporting. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this fulfillment order record was first created in the order management system. Serves as the audit trail anchor for record lineage. Distinct from submitted_timestamp which captures the business event time. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `credit_check_status` STRING COMMENT 'The outcome of the credit assessment performed during order processing. APPROVED: customer passed credit check. DECLINED: order blocked due to credit failure. WAIVED: credit check bypassed (e.g., existing premium customer). Drives order workflow progression in Oracle Communications OSM.. Valid values are `APPROVED|DECLINED|PENDING|WAIVED`',
    `decomposition_strategy` STRING COMMENT 'The strategy used by Oracle Communications OSM to decompose the fulfillment order into sub-orders and tasks for downstream OSS/BSS systems. Drives orchestration efficiency and parallel provisioning capabilities.. Valid values are `SEQUENTIAL|PARALLEL|CONDITIONAL|HYBRID`',
    `external_order_reference` STRING COMMENT 'The order reference number from an external or upstream system (e.g., Salesforce CRM opportunity ID, dealer portal order number, B2B customers purchase order number). Enables cross-system order tracing and reconciliation.',
    `fallout_category` STRING COMMENT 'Categorical classification of the order fallout reason, enabling structured reporting and trend analysis on order failure types. Complements fallout_reason with a standardized taxonomy for operational dashboards.. Valid values are `TECHNICAL|CREDIT_CHECK|VALIDATION|PROVISIONING|EXTERNAL_DEPENDENCY|REGULATORY`',
    `fallout_reason` STRING COMMENT 'Descriptive reason code or message explaining why the fulfillment order failed or was placed on hold during orchestration. Populated by Oracle Communications OSM when order_status transitions to FAILED or ON_HOLD. Critical for fallout management, root cause analysis, and process improvement.',
    `field_work_required` BOOLEAN COMMENT 'Indicates whether this fulfillment order requires a field technician dispatch for physical installation or maintenance (e.g., FTTH CPE installation, ONT provisioning). Drives integration with Granite Telecommunications Workforce Management for scheduling and dispatch.',
    `is_regulatory_order` BOOLEAN COMMENT 'Indicates whether this fulfillment order is subject to specific regulatory mandates (e.g., FCC MNP porting deadlines, emergency service provisioning, Ofcom consumer protection rules). Regulatory orders receive elevated priority and mandatory compliance reporting.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'The date and time when this fulfillment order record was last updated in the order management system. Used for change detection, incremental data loading, and audit compliance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `mnp_recipient_operator_code` STRING COMMENT 'For MNP_PORT_OUT orders: the network operator code of the recipient (gaining) operator to whom the mobile number is being ported. Used for inter-operator coordination and MNP regulatory reporting. Null for non-MNP order types.',
    `notes` STRING COMMENT 'Free-text notes or special instructions associated with the fulfillment order, entered by agents, customers, or automated systems. May include customer preferences, access instructions for field technicians, or escalation context. Not used for structured data.',
    `order_channel` STRING COMMENT 'The sales or service channel through which the fulfillment order was submitted. Used for channel performance analytics, cost-to-serve analysis, and omnichannel reporting. [ENUM-REF-CANDIDATE: ONLINE|RETAIL_STORE|CALL_CENTER|DEALER|SELF_SERVICE|B2B_PORTAL|FIELD_SALES — promote to reference product]',
    `order_number` STRING COMMENT 'Externally visible, human-readable business identifier for the fulfillment order. Communicated to customers, field technicians, and partner systems. Sourced from Oracle Communications Order and Service Management (OSM) as the canonical order reference number.. Valid values are `^ORD-[0-9]{10}$`',
    `order_priority` STRING COMMENT 'Business priority level assigned to the fulfillment order, influencing queue position in orchestration workflows and resource allocation. CRITICAL is reserved for regulatory-mandated orders (e.g., emergency services, MNP regulatory deadlines).. Valid values are `CRITICAL|HIGH|MEDIUM|LOW`',
    `order_source_system` STRING COMMENT 'The originating system or application from which the fulfillment order was submitted. Used for channel attribution, integration troubleshooting, and data lineage tracking. [ENUM-REF-CANDIDATE: OSM|SALESFORCE_CRM|SELF_SERVICE_PORTAL|B2B_PORTAL|DEALER_PORTAL|IVR|RETAIL_POS — promote to reference product]',
    `order_status` STRING COMMENT 'Current lifecycle state of the fulfillment order within the OSS/BSS orchestration workflow. Drives jeopardy management, SLA monitoring, and customer communication triggers. Sourced from Oracle Communications OSM order state machine.. Valid values are `PENDING|IN_PROGRESS|COMPLETED|CANCELLED|FAILED|ON_HOLD`',
    `order_type` STRING COMMENT 'Classification of the fulfillment order by the nature of the service change being requested. Drives orchestration workflow selection, SLA type assignment, and regulatory reporting. [ENUM-REF-CANDIDATE: NEW_ACTIVATION|UPGRADE|DOWNGRADE|DISCONNECTION|MNP_PORT_IN|MNP_PORT_OUT|CHANGE_OF_SERVICE — promote to reference product]',
    `porting_authorization_code` STRING COMMENT 'The Porting Authorization Code provided by the donor operator to authorize the number port. Required for MNP_PORT_IN orders to validate the customers right to port. Null for non-MNP order types.',
    `porting_number` STRING COMMENT 'The MSISDN (mobile phone number) being ported in MNP_PORT_IN or MNP_PORT_OUT orders. Classified as confidential PII as it directly identifies a subscriber. Null for non-MNP order types. Required for NRTRDE and TAP regulatory reporting.',
    `promised_completion_date` DATE COMMENT 'The date committed to the customer for order fulfillment completion. Used for SLA breach detection, customer communication, and regulatory compliance reporting. Distinct from SLA target hours — this is the customer-facing commitment date. Format: yyyy-MM-dd.',
    `regulatory_reference_code` STRING COMMENT 'The specific regulatory rule, mandate, or case reference code applicable to this fulfillment order when is_regulatory_order is True. Examples: FCC MNP case number, Ofcom compliance reference. Used for regulatory audit trails and compliance reporting.',
    `service_type` STRING COMMENT 'The type of telecommunications service being provisioned or modified by this fulfillment order. Drives workflow template selection, resource inventory allocation, and regulatory reporting categorization. [ENUM-REF-CANDIDATE: MOBILE|BROADBAND|FIBER|IPTV|VOIP|FIXED_LINE|IOT|ENTERPRISE_WAN — promote to reference product]',
    `sla_breach_threshold_hours` DECIMAL(18,2) COMMENT 'The number of hours elapsed from SLA measurement start at which the SLA is formally classified as BREACHED. Typically equals sla_target_hours but may differ for grace-period configurations. Triggers regulatory reporting obligations and penalty calculations.',
    `sla_breach_timestamp` TIMESTAMP COMMENT 'The precise date and time when the fulfillment order SLA was formally breached. Null for orders that have not breached. Used for regulatory reporting, penalty calculation, and SLA performance analytics. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `sla_measurement_end_event` STRING COMMENT 'The business event that stops the SLA measurement clock for this fulfillment order. Defines what constitutes successful completion for SLA purposes — e.g., SERVICE_ACTIVATED for mobile activations, CPE_INSTALLED for FTTH orders.. Valid values are `ORDER_COMPLETED|SERVICE_ACTIVATED|PORT_CONFIRMED|CPE_INSTALLED`',
    `sla_measurement_start_event` STRING COMMENT 'The business event that triggers the start of SLA measurement clock for this fulfillment order. Varies by order type and SLA type — regulatory MNP orders typically start at ORDER_ACCEPTED, while commercial orders may start at PAYMENT_CONFIRMED.. Valid values are `ORDER_SUBMITTED|ORDER_ACCEPTED|PAYMENT_CONFIRMED|CREDIT_APPROVED|FIELD_DISPATCH`',
    `sla_measurement_start_timestamp` TIMESTAMP COMMENT 'The precise date and time when the SLA measurement clock started for this fulfillment order, corresponding to the sla_measurement_start_event. Used as the reference point for all SLA elapsed-time calculations and regulatory compliance measurement. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `sla_status` STRING COMMENT 'Current SLA compliance status of the fulfillment order based on elapsed time versus SLA thresholds. ON_TRACK: within warning threshold. AT_RISK: between warning and breach thresholds. BREACHED: exceeded breach threshold. Primary field for jeopardy detection and regulatory compliance dashboards.. Valid values are `ON_TRACK|AT_RISK|BREACHED`',
    `sla_target_hours` DECIMAL(18,2) COMMENT 'The maximum number of hours within which the fulfillment order must be completed to meet the SLA commitment. Measured from the SLA measurement start event. Used for jeopardy detection and regulatory compliance reporting.',
    `sla_type` STRING COMMENT 'Classification of the SLA commitment governing this fulfillment order. REGULATORY: mandated by FCC/Ofcom/BEREC regulations (e.g., MNP porting windows). COMMERCIAL: standard commercial SLA per product tier. ENTERPRISE: premium SLA for enterprise/B2B customers.. Valid values are `REGULATORY|COMMERCIAL|ENTERPRISE`',
    `sla_warning_threshold_hours` DECIMAL(18,2) COMMENT 'The number of hours elapsed from SLA measurement start at which an AT_RISK warning is triggered for proactive jeopardy management. Must be less than sla_target_hours. Drives automated alerting in NOC and order management dashboards.',
    `submitted_timestamp` TIMESTAMP COMMENT 'The precise date and time when the fulfillment order was submitted by the customer or agent into the order management system. This is the principal business event timestamp and the anchor point for SLA measurement start calculations. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `workflow_template_name` STRING COMMENT 'The name of the OSM workflow template (order specification) used to orchestrate this fulfillment order. Determines the decomposition strategy, task sequence, and system interactions. Examples: MOBILE_NEW_ACTIVATION_V3, FTTH_PROVISIONING_V2.',
    CONSTRAINT pk_fulfillment_order PRIMARY KEY(`fulfillment_order_id`)
) COMMENT 'Core master record for every end-to-end order in the telecommunications lifecycle — new activations, upgrades, downgrades, disconnections, MNP port-in/port-out, and change-of-service requests. Sourced from Oracle Communications Order and Service Management (OSM). Captures order type, order channel, priority, customer reference, account reference, submitted timestamp, promised completion date, current order state, fallout reason, orchestration workflow instance ID, workflow template, decomposition strategy, SLA type (regulatory, commercial, enterprise), SLA target completion hours, warning threshold hours, breach threshold hours, SLA measurement start/end events, current SLA status (ON_TRACK, AT_RISK, BREACHED), and breach timestamp. This is the SSOT for order identity, lifecycle state, orchestration context, and SLA commitment within the order domain. All SLA monitoring, jeopardy detection, and regulatory compliance measurement derives from this master records SLA attributes.';

CREATE OR REPLACE TABLE `telecommunication_ecm`.`order`.`line` (
    `line_id` BIGINT COMMENT 'Unique surrogate identifier for each order line item within the fulfillment order management system. Primary key for the order_line entity. Role: TRANSACTION_LINE.',
    `addon_id` BIGINT COMMENT 'Foreign key linking to product.addon. Business justification: Addon products ordered as separate lines need direct catalog linkage for provisioning orchestration, billing setup, and quota management. Critical for value-added services fulfillment.',
    `address_id` BIGINT COMMENT 'Reference to the physical service delivery address for fixed-line, broadband, or FTTH order lines. Used for field dispatch scheduling in Granite Telecommunications Workforce Management and network infrastructure provisioning.',
    `billing_account_id` BIGINT COMMENT 'Foreign key linking to billing.billing_account. Business justification: Split billing: in telecom, individual lines (e.g., corporate-liable vs. individual-liable) can be billed to different billing accounts than the parent order. Line-level billing account assignment is r',
    `bundle_id` BIGINT COMMENT 'Foreign key linking to product.bundle. Business justification: Bundle orders require direct catalog reference for component validation, bundle pricing enforcement, discount calculation, and eligibility verification. Critical for multi-product offer fulfillment.',
    `corporate_account_id` BIGINT COMMENT 'Foreign key linking to enterprise.corporate_account. Business justification: Line-level corporate account tracking enables product-level revenue attribution per enterprise customer, supports multi-site service deployments, and facilitates usage analysis for account management ',
    `device_model_id` BIGINT COMMENT 'Foreign key linking to product.device_model. Business justification: Device line item fulfillment: order lines for handset upgrades or CPE installations must reference the specific device model for IMEI assignment, device inventory allocation, and device-specific provi',
    `carrier_id` BIGINT COMMENT 'Foreign key linking to interconnect.carrier. Business justification: MNP line-level donor carrier tracking: each MNP order line references the donor carrier for per-number porting coordination, settlement reconciliation, and regulatory per-MSISDN audit. Role prefix do',
    `enterprise_contract_id` BIGINT COMMENT 'Foreign key linking to enterprise.enterprise_contract. Business justification: Line-level contract linkage enables contract utilization tracking, commitment burn-down analysis, volume discount tier validation, and supports complex enterprise pricing schedules with product-specif',
    `fulfillment_order_id` BIGINT COMMENT 'Foreign key reference to the parent fulfillment order header. Satisfies TRANSACTION_LINE HEADER_REFERENCE category. Links this line item to its containing order transaction in Oracle Communications Order and Service Management.',
    `cpe_asset_id` BIGINT COMMENT 'Foreign key linking to inventory.cpe_asset. Business justification: Order lines provision CPE devices (modems, routers, ONTs) to customers. Real business need: installation tracking, warranty claims, device lifecycle management, asset return processing. Telecommunicat',
    `iot_deployment_id` BIGINT COMMENT 'Foreign key linking to enterprise.iot_deployment. Business justification: Order lines activating IoT SIMs must reference the IoT deployment they belong to for deployment-level activation tracking, SIM inventory management, and IoT deployment progress reporting. Telecom IoT ',
    `mnp_compliance_id` BIGINT COMMENT 'Foreign key linking to compliance.mnp_compliance. Business justification: MNP order lines (is_mnp_line=true, mnp_reference_number, msisdn) must be traceable to their mnp_compliance record for per-number porting SLA compliance verification and regulatory audit — each ported ',
    `msisdn_range_id` BIGINT COMMENT 'Foreign key linking to inventory.msisdn_range. Business justification: Order lines for mobile services assign a specific MSISDN drawn from a number range. Direct reference enables number inventory management, range utilization tracking, and regulatory number allocation r',
    `offering_id` BIGINT COMMENT 'Foreign key linking to product.offering. Business justification: Order line to product offering traceability: each order line represents a specific product offering being activated. Direct FK enables offering-level order volume reporting, product performance analyt',
    `ont_asset_id` BIGINT COMMENT 'Foreign key linking to inventory.ont_asset. Business justification: Fiber service order lines reference the ONT asset being installed or activated. Direct link enables fiber asset-to-order traceability, ONT assignment tracking, and asset lifecycle management. Parallel',
    `price_plan_id` BIGINT COMMENT 'Foreign key linking to product.price_plan. Business justification: Order lines must reference the specific price plan being ordered for accurate rating, billing, and revenue recognition. Critical for order-to-cash process and finance reconciliation in telecom operati',
    `promo_offer_id` BIGINT COMMENT 'Foreign key linking to product.promo_offer. Business justification: Promotional offer application per order line: each line can have a specific promo applied (e.g., 50% off first 3 months). Direct FK enables promo redemption tracking, budget consumption monitoring, an',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to sales.promotion. Business justification: Order lines carry applied promotions for discount validation and promotion redemption tracking. The plain promotion_code attribute on order.line denormalizes sales.promotion data. Replacing with a pro',
    `qos_profile_id` BIGINT COMMENT 'Foreign key linking to network.network_qos_profile. Business justification: Order lines for QoS-differentiated services (enterprise VPN, 5G slice, priority broadband) reference the specific QoS profile to be provisioned. Line-level QoS profile assignment drives provisioning p',
    `quote_line_id` BIGINT COMMENT 'Foreign key linking to sales.quote_line. Business justification: Quote-to-order line traceability: each order line is created from a specific quote line. Telecom commission calculation, revenue assurance, and price variance reporting require matching the delivered ',
    `rate_plan_id` BIGINT COMMENT 'Reference to the billing rate plan in Amdocs Revenue Management that governs the recurring and usage-based charges for the product on this order line. Established at order capture and used to configure the billing account upon fulfillment.',
    `sdwan_topology_id` BIGINT COMMENT 'Foreign key linking to enterprise.sdwan_topology. Business justification: Order lines provisioning SD-WAN CPE devices or circuits must reference the SD-WAN topology they are part of. Enables topology-level provisioning progress tracking and site activation sequencing — expe',
    `sim_stock_id` BIGINT COMMENT 'Foreign key linking to inventory.sim_stock. Business justification: Order lines activate specific SIM cards for mobile service. Real business need: SIM allocation tracking, activation audit trail, MNP porting coordination, inventory consumption. Existing iccid/imsi ar',
    `site_id` BIGINT COMMENT 'Foreign key linking to enterprise.site. Business justification: Line items provision services at specific enterprise sites (circuits, managed services, UC seats). Required for site-level service inventory management, capacity planning, and multi-site enterprise de',
    `slice_id` BIGINT COMMENT 'Foreign key linking to network.slice. Business justification: Order lines for 5G slice services reference the specific network slice being ordered. Enterprise customers ordering dedicated slices require line-level slice association for provisioning decomposition',
    `spec_id` BIGINT COMMENT 'Reference to the commercial product or service offering in the product catalog that this order line is acting upon (e.g., a specific mobile plan, broadband tier, or add-on). Satisfies TRANSACTION_LINE RESOURCE_REFERENCE category. Sourced from Netcracker OSS/BSS Product Catalog.',
    `subscriber_id` BIGINT COMMENT 'Foreign key linking to customer.subscriber. Business justification: Each order line activates, modifies, or terminates a specific subscribers service. Telecom order management requires subscriber-level linkage to drive SIM activation, MSISDN assignment, and provision',
    `svc_configuration_id` BIGINT COMMENT 'Foreign key linking to service.svc_configuration. Business justification: Each order line specifies the service configuration to be applied (bandwidth profile, APN, VoLTE settings). Linking line to svc_configuration enables product configuration traceability per order line,',
    `svc_instance_id` BIGINT COMMENT 'Reference to the provisioned service instance created or modified as a result of fulfilling this order line. Populated post-fulfillment by Oracle Communications Order and Service Management upon successful service activation. Links the commercial order line to the operational service layer.',
    `transmission_link_id` BIGINT COMMENT 'Foreign key linking to network.transmission_link. Business justification: Individual order lines for fixed broadband or leased-line services reference the specific transmission link being activated. Line-level transmission link association is needed for provisioning decompo',
    `uc_subscription_id` BIGINT COMMENT 'Foreign key linking to enterprise.uc_subscription. Business justification: Order lines provisioning UC seats (DID numbers, SIP trunks, feature packs) must reference the UC subscription being fulfilled. Enables UC subscription provisioning status tracking and seat count recon',
    `action_code` STRING COMMENT 'The fulfillment action to be performed for this line item. Drives order decomposition and workflow routing in Oracle Communications Order and Service Management. ADD = new activation; REMOVE = disconnection; MODIFY = change of service; SUSPEND = temporary suspension; RESUME = reactivation; PORT_IN = Mobile Number Portability (MNP) inbound; PORT_OUT = MNP outbound. [ENUM-REF-CANDIDATE: ADD|REMOVE|MODIFY|SUSPEND|RESUME|PORT_IN|PORT_OUT — promote to reference product]',
    `actual_completion_date` DATE COMMENT 'The actual date on which fulfillment of this order line was completed and the service was activated, modified, or disconnected. Compared against committed_delivery_date for SLA performance measurement and MTTR (Mean Time to Repair) analytics.',
    `channel_code` STRING COMMENT 'The sales or service channel through which this order line was initiated (e.g., ONLINE web portal, RETAIL_STORE, CALL_CENTER, DEALER partner, SELF_SERVICE app, B2B_PORTAL). Used for channel performance analytics, commission calculation, and order routing.. Valid values are `ONLINE|RETAIL_STORE|CALL_CENTER|DEALER|SELF_SERVICE|B2B_PORTAL`',
    `committed_delivery_date` DATE COMMENT 'The date committed to the customer for delivery or activation of the service on this line, as agreed at order capture. Used for SLA (Service Level Agreement) compliance monitoring and breach detection in service fulfillment reporting.',
    `contract_term_months` STRING COMMENT 'The minimum contract commitment period in months associated with the product on this order line (e.g., 0 for month-to-month, 12, 24, 36). Drives early termination fee (ETF) calculation and churn risk assessment in Amdocs Revenue Management.',
    `cpe_serial_number` STRING COMMENT 'Serial number of the CPE (Customer Premises Equipment) device — such as a router, ONT (Optical Network Terminal), or set-top box — assigned or dispatched as part of this order line. Used for inventory tracking in Netcracker OSS/BSS and field installation management.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this order line record was first created in Oracle Communications Order and Service Management. Used for order aging analysis, SLA measurement baseline, and audit trail compliance.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code applicable to the monetary values on this order line (e.g., USD, EUR, GBP). Required for multi-currency enterprise and wholesale order scenarios.. Valid values are `^[A-Z]{3}$`',
    `decomposition_state` STRING COMMENT 'Indicates the order decomposition processing state for this line within Oracle Communications Order and Service Management. Order decomposition translates a commercial product order line into technical service and resource fulfillment tasks across OSS systems. Critical for orchestration monitoring and fault management.. Valid values are `NOT_DECOMPOSED|DECOMPOSED|PARTIALLY_DECOMPOSED|DECOMPOSITION_FAILED`',
    `discount_amount` DECIMAL(18,2) COMMENT 'Monetary discount applied to this order line at the time of order capture, reflecting promotional offers, loyalty discounts, or negotiated enterprise pricing. Used by Amdocs Revenue Management for billing and revenue assurance reconciliation.',
    `early_termination_fee` DECIMAL(18,2) COMMENT 'The early termination fee amount applicable if the customer cancels this order line before the end of the contract_term_months. Calculated at order capture based on the rate plan and contract term. Used by Amdocs Revenue Management for billing upon disconnection.',
    `fallout_description` STRING COMMENT 'Free-text description providing additional context for the order line fallout or failure, supplementing the fallout_reason_code. Captured by Oracle Communications Order and Service Management workflow engine for manual intervention and customer communication.',
    `fallout_reason_code` STRING COMMENT 'Standardized code indicating the reason for order line fallout or failure during fulfillment orchestration (e.g., CREDIT_FAIL, INVENTORY_UNAVAILABLE, ADDRESS_NOT_SERVICEABLE, PORTING_REJECTED). Used for fallout management, root cause analysis, and process improvement in Oracle Communications Order and Service Management.',
    `iccid` STRING COMMENT 'The unique SIM card identifier (ICCID) assigned to this order line for mobile service activations. Used for SIM provisioning in HLR/HSS/UDM systems and inventory management in Netcracker OSS/BSS. Classified as confidential as it identifies a specific subscriber SIM.. Valid values are `^[0-9]{19,20}$`',
    `imsi` STRING COMMENT 'The International Mobile Subscriber Identity assigned to the SIM for this order line. Used for subscriber provisioning in HSS (Home Subscriber Server) and UDM (Unified Data Management) systems. Restricted PII as it uniquely identifies a mobile subscriber globally.. Valid values are `^[0-9]{15}$`',
    `is_esim` BOOLEAN COMMENT 'Indicates whether this order line involves an eSIM (Embedded SIM) provisioning rather than a physical SIM card. When TRUE, triggers eSIM profile download orchestration via GSMA SGP.22 RSP (Remote SIM Provisioning) instead of physical SIM dispatch.',
    `is_mnp_line` BOOLEAN COMMENT 'Indicates whether this order line involves a Mobile Number Portability (MNP) port-in or port-out transaction. When TRUE, triggers MNP-specific workflow orchestration including donor operator notification and number portability clearinghouse coordination.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'The date and time when this order line record was last updated in Oracle Communications Order and Service Management. Used for change detection in ETL pipelines, audit trail, and concurrency control.',
    `line_number` STRING COMMENT 'Sequential position of this line item within the parent order. Used for ordering, display, and referencing individual lines in multi-line orders (e.g., line 1 = mobile plan, line 2 = broadband, line 3 = MNP port-in). Satisfies TRANSACTION_LINE LINE_SEQUENCE category.',
    `line_status` STRING COMMENT 'Current fulfillment lifecycle state of this individual order line. Tracks granular progress independently from the parent order header status, enabling partial fulfillment scenarios where some lines complete while others are held. Sourced from Oracle Communications Order and Service Management workflow engine.. Valid values are `PENDING|IN_PROGRESS|COMPLETED|FAILED|CANCELLED|ON_HOLD`',
    `mnp_reference_number` STRING COMMENT 'Unique reference number assigned by the number portability clearinghouse or regulatory body for a PORT_IN or PORT_OUT order line. Used for inter-operator tracking, regulatory compliance reporting to FCC/Ofcom/BEREC, and dispute resolution.',
    `net_price` DECIMAL(18,2) COMMENT 'Net commercial price for this order line after applying discounts (unit_price × quantity − discount_amount). Represents the agreed charge basis passed to Amdocs Revenue Management for billing. Distinct from tax-inclusive total.',
    `priority` STRING COMMENT 'Processing priority assigned to this order line for fulfillment queue management. HIGH and CRITICAL priorities are used for enterprise SLA orders, regulatory-mandated activations, and emergency service restorations. Drives scheduling in Oracle Communications Order and Service Management.. Valid values are `LOW|NORMAL|HIGH|CRITICAL`',
    `product_name` STRING COMMENT 'Human-readable name of the product or service being ordered on this line (e.g., 5G Unlimited Plan, FTTH 1Gbps Broadband, VoLTE Add-On). Denormalized from the product catalog for operational reporting and customer-facing order confirmations.',
    `product_type` STRING COMMENT 'High-level classification of the product or service being ordered on this line. Drives workflow routing, provisioning system selection, and reporting segmentation. [ENUM-REF-CANDIDATE: MOBILE|BROADBAND|FIXED_LINE|IPTV|VOIP|IOT|ENTERPRISE|ADD_ON — promote to reference product]',
    `quantity` STRING COMMENT 'Number of units of the product or service being ordered on this line. Typically 1 for most telecom service lines but may be greater for bulk SIM orders, enterprise seat licenses, or CPE equipment orders. Satisfies TRANSACTION_LINE LINE_QUANTITY category.',
    `requested_start_date` DATE COMMENT 'The customer-requested date on which the product or service on this line should become active. Drives service provisioning scheduling in Oracle Communications Order and Service Management and SLA commitment tracking.',
    `requires_field_visit` BOOLEAN COMMENT 'Indicates whether fulfillment of this order line requires a field technician visit (e.g., FTTH installation, CPE installation, ONT splicing). When TRUE, triggers work order creation and field dispatch scheduling in Granite Telecommunications Workforce Management.',
    `service_type` STRING COMMENT 'Billing and operational service type for this order line, distinguishing postpaid subscription, prepaid (Comverse ONE), hybrid, MVNO (Mobile Virtual Network Operator) resale, or wholesale service arrangements. Determines downstream billing system routing.. Valid values are `POSTPAID|PREPAID|HYBRID|MVNO|WHOLESALE`',
    `source_system_code` STRING COMMENT 'The native identifier of this order line record in the originating operational system (Oracle Communications Order and Service Management). Enables lineage tracing, reconciliation, and idempotent upsert processing in the Databricks Silver Layer.',
    `technology_type` STRING COMMENT 'Network access technology associated with the product on this order line (e.g., LTE, 5G NR, FTTH/GPON, DSL). Used for network provisioning routing to Ericsson Network Manager or Nokia NetAct, capacity planning, and technology migration analytics. [ENUM-REF-CANDIDATE: 2G|3G|4G_LTE|5G_NR|FTTH_GPON|FTTB|DSL|CABLE|FIXED_WIRELESS — promote to reference product]',
    `unit_price` DECIMAL(18,2) COMMENT 'Commercial price per unit for the product or service on this line at the time of order placement, before discounts and taxes. Represents the catalog or negotiated price used for billing rate plan association in Amdocs Revenue Management. Satisfies TRANSACTION_LINE LINE_VALUE_OR_RESULT category.',
    CONSTRAINT pk_line PRIMARY KEY(`line_id`)
) COMMENT 'Individual line item within a fulfillment order representing a single product or service action (add, remove, modify, suspend, resume). Each line carries the commercial product reference, requested action code, quantity, requested service start date, line-level status, and decomposition state. Supports multi-line orders where a customer simultaneously activates a mobile plan, adds a broadband service, and ports a number in a single order transaction.';

CREATE OR REPLACE TABLE `telecommunication_ecm`.`order`.`status_history` (
    `status_history_id` BIGINT COMMENT 'Unique surrogate identifier for each order status history record. Primary key of the order_status_history data product. Immutable once assigned.',
    `amendment_id` BIGINT COMMENT 'Foreign key linking to order.amendment. Business justification: The status_history table explicitly tracks post-submission amendments — it has amendment_type, amendment_status, amended_field_name, amendment_request_timestamp, cost_delta, original_value, and new_va',
    `appointment_id` BIGINT COMMENT 'Reference to the field service appointment associated with this order history record, particularly relevant for APPOINTMENT_CHANGE amendments or transitions triggered by appointment outcomes. Links to Granite Telecommunications Workforce Management scheduling records.',
    `customer_account_id` BIGINT COMMENT 'Reference to the customer account associated with the fulfillment order. Enables customer-level SLA tracking, dispute resolution, and churn analysis across the order lifecycle.',
    `fulfillment_order_id` BIGINT COMMENT 'Reference to the parent fulfillment order for which this status history record was created. Links every history entry back to its originating order in Oracle Communications Order and Service Management.',
    `noc_incident_id` BIGINT COMMENT 'Foreign key linking to assurance.noc_incident. Business justification: Order status transitions caused by NOC incidents (e.g., order suspended due to network outage) must reference the incident for SLA suspension justification and regulatory audit trails. status_history ',
    `provisioning_order_id` BIGINT COMMENT 'Reference to the decomposed service order generated from the parent fulfillment order in Oracle Communications Order and Service Management or Netcracker OSS/BSS Suite. Supports traceability between commercial order history and service fulfillment execution.',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: status_history.is_regulatory_reportable flags transitions that must be reported under a specific regulatory obligation (e.g., MNP porting status changes within mandated windows). Linking to the govern',
    `trouble_ticket_id` BIGINT COMMENT 'Reference to a ServiceNow ITSM trouble ticket or incident raised in association with this state transition or amendment (e.g., a FALLOUT event that triggered an incident). Null when no ticket is associated. Supports cross-system traceability for fault management.',
    `task_id` BIGINT COMMENT 'Identifier of the specific workflow task or orchestration step within Oracle Communications Order and Service Management that generated this history record. Enables traceability from the history record back to the originating workflow execution for technical root-cause analysis.',
    `actor_system` STRING COMMENT 'Name of the OSS/BSS system that originated the transition or amendment event (e.g., Oracle Communications Order and Service Management, Netcracker OSS/BSS Suite, Salesforce CRM, ServiceNow ITSM). Enables source-system traceability for fallout root-cause analysis.',
    `actor_type` STRING COMMENT 'Categorizes the type of actor that triggered the state transition or amendment. SYSTEM indicates an automated OSS/BSS process; AGENT indicates a human CSR or field technician; CUSTOMER indicates a self-service action; SUPERVISOR indicates a management override; AUTOMATED_RULE indicates a policy engine or workflow rule.. Valid values are `SYSTEM|AGENT|CUSTOMER|SUPERVISOR|AUTOMATED_RULE`',
    `amended_field_name` STRING COMMENT 'For amendment records, the logical name of the order attribute that was changed (e.g., installation_address, appointment_date, selected_product_id, service_configuration_value). Provides context for interpreting original_value and new_value. Null for state transition records.',
    `amendment_request_timestamp` TIMESTAMP COMMENT 'Date and time when the amendment was formally requested by the customer or agent. Distinct from transition_timestamp (which records when the event was processed). Used to measure amendment processing lead time and SLA compliance. Null for state transition records. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `amendment_status` STRING COMMENT 'Current processing status of the amendment request. PENDING: awaiting review; APPROVED: authorized but not yet applied to the order; REJECTED: denied by agent or system rule; APPLIED: successfully incorporated into the active order. Null for state transition records.. Valid values are `PENDING|APPROVED|REJECTED|APPLIED`',
    `amendment_type` STRING COMMENT 'For amendment records, classifies the type of post-submission change requested. Null for state transition records. [ENUM-REF-CANDIDATE: APPOINTMENT_CHANGE|PRODUCT_SELECTION_CHANGE|ADDRESS_CHANGE|SERVICE_CONFIGURATION_CHANGE|CONTACT_CHANGE|PAYMENT_METHOD_CHANGE — promote to reference product]',
    `cost_delta` DECIMAL(18,2) COMMENT 'For amendment records, the incremental cost impact (positive or negative, in the account currency) resulting from the amendment — e.g., a product selection change that increases or decreases the order value. Null for state transition records and zero-cost amendments. Used for revenue assurance and billing reconciliation.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this history record was first written to the Silver Layer lakehouse. Distinct from transition_timestamp (the business event time). Used for data pipeline monitoring, late-arrival detection, and audit trail completeness verification. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code applicable to the cost_delta amount (e.g., USD, EUR, GBP). Null when cost_delta is null. Supports multi-currency operations across international markets.. Valid values are `^[A-Z]{3}$`',
    `duration_in_state_seconds` BIGINT COMMENT 'Number of seconds the order spent in the previous_state before transitioning to new_state. Calculated at ingestion time as the difference between this records transition_timestamp and the prior records transition_timestamp for the same order. Used for SLA bottleneck analysis and process mining.',
    `fallout_category` STRING COMMENT 'When new_state is FALLOUT, classifies the root-cause category of the fallout event (e.g., PROVISIONING_FAILURE, CREDIT_REJECTION, ADDRESS_VALIDATION_FAILURE, MNP_REJECTION, NETWORK_CAPACITY, SYSTEM_ERROR). Null for non-FALLOUT transitions. Essential for fallout root-cause analysis and NOC/OSS remediation workflows.',
    `fallout_resolution_code` STRING COMMENT 'Standardized code indicating how a FALLOUT condition was resolved (e.g., AUTO_RETRY_SUCCESS, MANUAL_INTERVENTION, ORDER_CANCELLED, REROUTED_TO_ALTERNATE_RESOURCE). Populated when transitioning out of FALLOUT state. Null for non-FALLOUT records.',
    `is_regulatory_reportable` BOOLEAN COMMENT 'Indicates whether this history record is subject to regulatory reporting obligations (e.g., FCC order completion reporting, BEREC quality-of-service metrics, OFCOM service provisioning KPIs). True flags records that must be included in regulatory submissions.',
    `mnp_reference_number` STRING COMMENT 'For MNP port-in or port-out order types, the inter-operator MNP reference number assigned by the number portability clearinghouse. Null for non-MNP orders. Required for GSMA MNP compliance reporting and inter-carrier dispute resolution.',
    `new_state` STRING COMMENT 'The order lifecycle state entered as a result of this transition. For amendment records, reflects the order state at the time the amendment was recorded. Valid states include SUBMITTED, VALIDATED, IN_PROGRESS, PENDING_PROVISIONING, COMPLETED, CANCELLED, FALLOUT. [ENUM-REF-CANDIDATE: SUBMITTED|VALIDATED|IN_PROGRESS|PENDING_PROVISIONING|COMPLETED|CANCELLED|FALLOUT — promote to reference product]',
    `new_value` DECIMAL(18,2) COMMENT 'For amendment records, the proposed or applied new value for the amended field (serialized as string for flexibility across amendment types). Null for state transition records. Paired with original_value to provide a complete before/after audit record.',
    `original_value` DECIMAL(18,2) COMMENT 'For amendment records, the value of the amended field before the change was applied (serialized as string for flexibility across amendment types). Null for state transition records. Supports dispute resolution and regulatory audit trails.',
    `override_flag` BOOLEAN COMMENT 'Indicates whether a standard business rule, credit policy, or SLA policy was overridden to process this transition or amendment. When True, override_justification must be populated. Supports compliance monitoring and exception reporting.',
    `override_justification` STRING COMMENT 'Free-text justification provided by a supervisor or authorized agent when a standard business rule or SLA policy is overridden to approve an amendment or force a state transition. Required for compliance audit trails when override_flag is True.',
    `previous_state` STRING COMMENT 'The order lifecycle state immediately before this transition occurred. Null for the initial SUBMITTED state entry. Valid states include SUBMITTED, VALIDATED, IN_PROGRESS, PENDING_PROVISIONING, COMPLETED, CANCELLED, FALLOUT. [ENUM-REF-CANDIDATE: SUBMITTED|VALIDATED|IN_PROGRESS|PENDING_PROVISIONING|COMPLETED|CANCELLED|FALLOUT — promote to reference product]',
    `reason_code` STRING COMMENT 'Standardized code identifying the business reason for the state transition or amendment (e.g., CREDIT_CHECK_FAILED, PROVISIONING_TIMEOUT, CUSTOMER_REQUESTED_CANCEL, MNP_PORT_DELAY, NETWORK_CAPACITY_UNAVAILABLE). Used for fallout root-cause analysis and SLA reporting.',
    `reason_description` STRING COMMENT 'Free-text narrative providing additional context for the state transition or amendment reason, supplementing the structured reason_code. May include agent notes, system error messages, or customer-provided explanations captured at the time of the event.',
    `record_type` STRING COMMENT 'Discriminator indicating whether this history record captures a state transition (order lifecycle state change) or a post-submission amendment (customer or agent-initiated change to order attributes). Drives downstream processing logic and reporting segmentation.. Valid values are `STATE_TRANSITION|AMENDMENT`',
    `sequence_number` STRING COMMENT 'Monotonically increasing integer representing the chronological order of history records for a given order_id. Sequence 1 is the initial SUBMITTED state entry. Enables ordered reconstruction of the complete order lifecycle and detection of out-of-sequence processing anomalies.',
    `sla_reset_flag` BOOLEAN COMMENT 'Indicates whether this state transition or amendment triggered a reset of the order fulfillment SLA clock. True when the SLA measurement window is restarted (e.g., due to a customer-requested amendment or a FALLOUT recovery). Critical for accurate SLA compliance reporting to FCC and BEREC.',
    `sla_target_timestamp` TIMESTAMP COMMENT 'The committed SLA completion deadline applicable at the time of this history record. If sla_reset_flag is True, this reflects the recalculated SLA target post-reset. Enables point-in-time SLA compliance measurement and regulatory reporting. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `source_record_reference` STRING COMMENT 'The native primary key or event identifier of this record in the originating source system (e.g., the Oracle Communications Order and Service Management order history event ID). Enables reverse traceability from the Silver Layer back to the operational system for reconciliation and reprocessing.',
    `source_system` STRING COMMENT 'Name of the operational system of record from which this history record was sourced (e.g., Oracle Communications Order and Service Management, Netcracker OSS/BSS Suite, Salesforce CRM). Supports data lineage tracking and multi-system reconciliation in the Silver Layer lakehouse.',
    `transition_timestamp` TIMESTAMP COMMENT 'The precise date and time (with timezone offset) at which the state transition or amendment event occurred. This is the principal business event timestamp used for SLA measurement, fallout root-cause analysis, and regulatory audit trails. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this history record was last modified in the Silver Layer (e.g., due to a late-arriving amendment status update or correction). For a fully immutable audit trail, updates should be rare and logged. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    CONSTRAINT pk_status_history PRIMARY KEY(`status_history_id`)
) COMMENT 'Immutable audit trail of every state transition and post-submission amendment for a fulfillment order throughout its lifecycle — from SUBMITTED through VALIDATED, IN_PROGRESS, PENDING_PROVISIONING, COMPLETED, CANCELLED, or FALLOUT. For state transitions: records previous state, new state, transition timestamp, triggering actor (system or user), and reason code. For amendments: records amendment type (appointment change, product selection change, address change, service configuration change), original value, new value, amendment request timestamp, amendment status (PENDING, APPROVED, REJECTED, APPLIED), approving agent reference, impact assessment (SLA reset flag, cost delta), and override justification. This is the SSOT for all order change history — both system-driven state transitions and customer/agent-initiated amendments. Essential for SLA measurement, fallout root-cause analysis, dispute resolution, and regulatory audit trails required by FCC and BEREC.';

CREATE OR REPLACE TABLE `telecommunication_ecm`.`order`.`task` (
    `task_id` BIGINT COMMENT 'Unique surrogate identifier for each decomposed order task record generated by the Oracle Communications Order and Service Management (OSM) orchestration engine. Primary key for the order_task data product.',
    `cpe_asset_id` BIGINT COMMENT 'Foreign key linking to inventory.cpe_asset. Business justification: Field dispatch tasks for CPE installation, swap, or fault resolution directly reference the physical CPE asset being worked on. Technicians need direct asset lookup for field operations without traver',
    `depot_id` BIGINT COMMENT 'Foreign key linking to workforce.depot. Business justification: Field-work tasks are dispatched from specific depots managing territory coverage, parts inventory, and technician availability. Critical for logistics planning, resource allocation, and technician dis',
    `fiber_cable_id` BIGINT COMMENT 'Foreign key linking to inventory.fiber_cable. Business justification: Fiber splicing, repair, and new-connection tasks reference the specific fiber cable segment being worked on. Field operations for fiber infrastructure require direct cable asset reference for dispatch',
    `fulfillment_order_id` BIGINT COMMENT 'Reference to the parent commercial order header that contains the order line from which this task was decomposed. Enables direct navigation from task to top-level order for end-to-end fulfillment traceability.',
    `line_id` BIGINT COMMENT 'Reference to the parent commercial order line from which this task was decomposed. Establishes the traceability chain from commercial order line to atomic fulfillment task within the OSM orchestration engine.',
    `managed_service_id` BIGINT COMMENT 'Foreign key linking to enterprise.managed_service. Business justification: Provisioning tasks target specific managed service instances (SD-WAN, MPLS, managed security) for configuration changes, capacity modifications, or service updates. Required for service orchestration ',
    `mnp_transaction_id` BIGINT COMMENT 'Foreign key linking to interconnect.mnp_transaction. Business justification: MNP task execution tracking: tasks for HLR/HSS updates, routing number changes, and donor network notifications are created per mnp_transaction. Linking enables operational tracking of which tasks exe',
    `element_id` BIGINT COMMENT 'Foreign key linking to network.element. Business justification: Provisioning tasks execute configuration commands against specific network elements (configure subscriber profile on BRAS, provision VLAN on switch). Core to automated service fulfillment workflows an',
    `network_equipment_id` BIGINT COMMENT 'Foreign key linking to inventory.network_equipment. Business justification: Field tasks for network equipment maintenance, swap, or configuration (DSLAM, switch, router) reference the specific inventory asset. Equipment maintenance scheduling and asset lifecycle tracking requ',
    `noc_incident_id` BIGINT COMMENT 'Reference to the ServiceNow ITSM incident or change request raised in response to a task fallout or execution failure. Populated when fallout_indicator is True and an ITSM ticket has been created for manual resolution. Enables cross-system traceability between order fulfillment and incident management.',
    `ont_asset_id` BIGINT COMMENT 'Foreign key linking to inventory.ont_asset. Business justification: Decomposed order tasks configure ONT devices in child systems (OSS/BSS/EMS). Real business need: task-level device tracking, fallout resolution, technician dispatch coordination, configuration rollbac',
    `ran_cell_id` BIGINT COMMENT 'Foreign key linking to network.ran_cell. Business justification: Field and provisioning tasks for RAN cell activation, configuration, or maintenance reference the specific cell. Workforce management and OSS task orchestration for mobile network operations require c',
    `site_id` BIGINT COMMENT 'Foreign key linking to enterprise.enterprise_site. Business justification: Field tasks (installation, maintenance, fault resolution) are performed at enterprise sites. Direct link enables site-level task scheduling, workforce dispatch optimization, and enterprise site servic',
    `slice_id` BIGINT COMMENT 'Foreign key linking to network.slice. Business justification: Orchestration tasks for 5G slice instantiation, modification, or decommissioning reference the specific slice. Order fulfillment decomposition for slice services generates tasks that must be tied to t',
    `svc_configuration_id` BIGINT COMMENT 'Foreign key linking to service.svc_configuration. Business justification: Provisioning tasks apply specific service configurations (QoS profiles, APN settings, eSIM profiles). Linking task to svc_configuration enables operational traceability of which configuration was appl',
    `svc_instance_id` BIGINT COMMENT 'Reference to the service instance in the Netcracker service inventory that this task provisions, modifies, or deactivates. Links the fulfillment task to the service layer for end-to-end service lifecycle traceability.',
    `technician_id` BIGINT COMMENT 'Reference to the field technician assigned to execute this task in Granite Telecommunications Workforce Management. Populated for CPE dispatch and GPON ONT activation tasks requiring physical field intervention. Drives field dispatch scheduling and route optimisation.',
    `task_technician_id` BIGINT COMMENT 'Reference to the network or physical resource (e.g., GPON ONT, CPE device, IP address, MSISDN, SIM) in the Netcracker resource inventory that this task acts upon. Enables resource-level fulfillment traceability and inventory reconciliation.',
    `transmission_link_id` BIGINT COMMENT 'Foreign key linking to network.transmission_link. Business justification: Provisioning and field tasks targeting transmission links (fiber activation, leased-line commissioning, wavelength provisioning) must reference the specific link. Task management and workforce dispatc',
    `trouble_ticket_id` BIGINT COMMENT 'Foreign key linking to assurance.trouble_ticket. Business justification: Order tasks are created to resolve trouble tickets — field technician dispatch, configuration changes, and network fixes are modeled as tasks linked to the originating trouble ticket. Telecom workforc',
    `work_order_id` BIGINT COMMENT 'Reference to the field work order in Granite Telecommunications Workforce Management associated with this task. Populated for tasks requiring physical field dispatch (CPE installation, GPON ONT activation). Links fulfillment task to field operations scheduling.',
    `actual_start_time` TIMESTAMP COMMENT 'The actual date and time at which execution of this task commenced in the downstream target system. Compared against scheduled_start_time to measure scheduling adherence and identify orchestration delays.',
    `automation_indicator` BOOLEAN COMMENT 'Boolean flag indicating whether this task was executed automatically by the OSM orchestration engine (True) or required manual intervention by an operations team member (False). Key metric for measuring fulfillment automation rates and identifying candidates for further automation.',
    `child_order_type` STRING COMMENT 'Classifies the type of lower-level order generated by the decomposition of the parent commercial order line. Distinguishes between service-layer orders (service_order), resource-layer orders (resource_order), and network-layer orders (network_order) per TM Forum SID decomposition hierarchy.. Valid values are `service_order|resource_order|network_order`',
    `child_system_target` STRING COMMENT 'Identifies the downstream OSS/BSS system to which this task is dispatched for execution (e.g., HLR, HSS, GPON-OLT, Amdocs, Netcracker, Ericsson Network Manager). Critical for cross-system orchestration traceability and fallout diagnosis.',
    `child_system_task_ref` STRING COMMENT 'The task or work order identifier assigned by the downstream target system (e.g., Ericsson Network Manager work order ID, Netcracker service order number, ServiceNow change request number). Enables cross-system correlation and reconciliation between OSM and downstream fulfillment systems.',
    `completion_time` TIMESTAMP COMMENT 'The date and time at which this task reached a terminal state (completed, failed, or cancelled) in the OSM orchestration engine. Used to calculate task duration, SLA compliance, and MTTR for fulfillment operations.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time at which this order task record was first created in the OSM orchestration engine following order decomposition. Serves as the audit creation timestamp and the baseline for SLA elapsed-time calculations.',
    `data_classification` STRING COMMENT 'Data governance classification level for this order task record per the enterprise data classification policy. Determines access controls, retention policies, and handling requirements in the Databricks Lakehouse Silver Layer.. Valid values are `restricted|confidential|internal|public`',
    `decomposition_rule_version` STRING COMMENT 'Version of the decomposition rule applied at the time this task was generated. Supports impact analysis when orchestration rules are updated and enables reproducibility of order decomposition logic for audit purposes.',
    `dependency_task_ids` STRING COMMENT 'Comma-separated list of order_task_id values that must reach completed status before this task can begin execution. Captures the dependency chain within the OSM orchestration workflow to enforce correct fulfillment sequencing (e.g., HLR provisioning must complete before VoLTE IMS registration).',
    `due_time` TIMESTAMP COMMENT 'The SLA-committed deadline by which this task must reach completed status. Derived from the parent orders committed delivery date and the tasks position in the fulfillment sequence. Breach of this timestamp triggers escalation workflows.',
    `error_code` STRING COMMENT 'Machine-readable error code returned by the downstream target system upon task execution failure (e.g., HLR error codes, GPON provisioning error codes, HTTP status codes from REST APIs). Distinct from fallout_reason_code which is an OSM-normalised classification.',
    `execution_duration_seconds` STRING COMMENT 'The elapsed time in seconds between actual_start_time and completion_time for this task. Populated upon task completion. Used for provisioning performance benchmarking, SLA analysis, and identification of slow downstream systems contributing to order fulfillment delays.',
    `execution_sequence` STRING COMMENT 'Numeric ordering position of this task within the overall order fulfillment workflow. Determines the sequence in which tasks are executed relative to sibling tasks on the same order line. Lower values execute first.',
    `fallout_detail` STRING COMMENT 'Free-text description of the error or exception that caused this task to fall out, as returned by the downstream target system or the OSM orchestration engine. Provides diagnostic context for manual resolution by NOC or BSS operations teams.',
    `fallout_indicator` BOOLEAN COMMENT 'Boolean flag indicating whether this task has entered fallout status requiring manual intervention or escalation. True when the task has exceeded retry limits or encountered an unrecoverable error. Drives fallout management queues in OSM and ServiceNow ITSM.',
    `fallout_reason_code` STRING COMMENT 'Standardised code identifying the root cause of task fallout (e.g., DOWNSTREAM_TIMEOUT, INVALID_MSISDN, RESOURCE_UNAVAILABLE, GPON_PORT_EXHAUSTED, HLR_REJECT). Populated when fallout_indicator is True. Used for fallout trend analysis and systemic issue identification.',
    `imsi` STRING COMMENT 'The International Mobile Subscriber Identity (IMSI) of the SIM card being provisioned by this task. Populated for HLR/HSS provisioning and SIM activation tasks. A 15-digit globally unique subscriber identifier per 3GPP standards. Classified as confidential as it uniquely identifies a subscriber on the network.. Valid values are `^[0-9]{15}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time at which this order task record was most recently modified in the OSM orchestration engine. Tracks state transitions, retry attempts, and synchronisation updates for audit and change-management purposes.',
    `max_retry_limit` STRING COMMENT 'The maximum number of retry attempts permitted for this task before it is automatically escalated to fallout management. Configured per task type and downstream system target in the OSM orchestration engine.',
    `msisdn` STRING COMMENT 'The Mobile Station International Subscriber Directory Number (MSISDN) — the subscribers mobile phone number — associated with the provisioning action performed by this task. Populated for HLR/HSS provisioning, SIM activation, and MNP tasks. Classified as confidential as it is a customer-linked network identifier.. Valid values are `^+?[1-9]d{6,14}$`',
    `network_technology` STRING COMMENT 'The network technology domain relevant to this provisioning task. Determines which network management system (Ericsson Network Manager for RAN, Nokia NetAct for core, OLT for GPON) handles execution. [ENUM-REF-CANDIDATE: 4G_LTE|5G_NR|FTTH_GPON|VoLTE|IMS|MPLS|SD_WAN|DSLAM|fixed_wireless|eSIM|NFV|SDN — promote to reference product]',
    `ont_serial_number` STRING COMMENT 'Serial number of the Optical Network Terminal (ONT) / Customer Premises Equipment (CPE) being activated or configured by this task. Populated for GPON ONT activation and CPE dispatch tasks. Used for FTTH inventory reconciliation and field technician dispatch coordination.',
    `order_action_type` STRING COMMENT 'The commercial order action that triggered the creation of this task. Inherited from the parent order line and used to determine the appropriate provisioning logic in the downstream target system. MNP (Mobile Number Portability) port-in/port-out tasks require coordination with GSMA NRTRDE and TAP processes. [ENUM-REF-CANDIDATE: new_activation|upgrade|downgrade|disconnection|mnp_port_in|mnp_port_out|change_of_service — 7 candidates stripped; promote to reference product]',
    `priority` STRING COMMENT 'Business priority level assigned to this task, inherited from the parent order or overridden by the OSM orchestration engine based on customer segment, SLA tier, or order type. Drives execution queue ordering and resource allocation in fulfillment operations.. Valid values are `critical|high|medium|low`',
    `retry_count` STRING COMMENT 'Number of times execution of this task has been retried following a failure or timeout. Used to enforce maximum retry thresholds, trigger fallout management escalation, and analyse systemic provisioning failure patterns across downstream systems.',
    `scheduled_start_time` TIMESTAMP COMMENT 'The planned date and time at which this task is scheduled to begin execution within the OSM orchestration engine. Used for SLA target calculation, capacity planning, and workforce scheduling in field dispatch scenarios.',
    `sla_breach_indicator` BOOLEAN COMMENT 'Boolean flag indicating whether this task has breached its SLA due_time commitment. Set to True when completion_time exceeds due_time, or when the task remains in a non-terminal state past due_time. Drives SLA reporting, customer compensation workflows, and regulatory compliance reporting to FCC/Ofcom.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this order task record originates (e.g., OSM, Netcracker, Amdocs). Used for data lineage tracking in the Databricks Silver Layer and cross-system reconciliation in the Revenue Assurance domain.',
    `sync_status` STRING COMMENT 'Indicates the synchronisation state of this task with the downstream target system. Tracks whether the task execution result has been confirmed and reconciled back to the OSM orchestration engine from the child system (e.g., HLR, GPON-OLT, Netcracker).. Valid values are `synced|pending_sync|sync_failed|not_applicable`',
    `task_number` STRING COMMENT 'Externally visible, human-readable business identifier for this order task as assigned by the OSM orchestration engine (e.g., TSK-2024-00123456). Used in NOC dashboards, trouble tickets, and cross-system correlation.',
    `task_status` STRING COMMENT 'Current lifecycle state of the order task within the OSM orchestration engine. Drives SLA monitoring, fallout management, and retry logic. Valid states: pending (awaiting execution), in_progress (actively executing), completed (successfully fulfilled), failed (execution error), cancelled (task voided), suspended (paused pending dependency resolution).. Valid values are `pending|in_progress|completed|failed|cancelled|suspended`',
    `task_type` STRING COMMENT 'Classifies the atomic fulfillment action this task represents within the OSM orchestration workflow. Drives routing to the appropriate downstream system and execution handler. [ENUM-REF-CANDIDATE: hlr_hss_provisioning|ip_address_assignment|cpe_dispatch|gpon_ont_activation|number_portability_submission|sim_activation|service_configuration|esim_provisioning|voip_registration|ims_registration|mpls_circuit_setup|ran_configuration — promote to reference product]',
    CONSTRAINT pk_task PRIMARY KEY(`task_id`)
) COMMENT 'Granular decomposed work task generated by OSM order orchestration engine from a specific order line during order decomposition. Represents both the decomposition mapping (tracing commercial order line to lower-level service/resource/network orders) and the atomic fulfillment execution step (HLR/HSS provisioning, IP address assignment, CPE dispatch, GPON ONT activation, number portability submission). Captures parent order line reference, decomposition rule applied, child system target, child order type (service_order, resource_order, network_order), task type, execution sequence, dependency chain, start time, completion time, retry count, task-level status, synchronisation status with downstream systems, creation timestamp, and fallout detail. Provides full decomposition traceability from commercial order line through orchestration logic to network provisioning action — serving as the SSOT for both order decomposition mapping and task execution within this domain.';

CREATE OR REPLACE TABLE `telecommunication_ecm`.`order`.`fallout` (
    `fallout_id` BIGINT COMMENT 'Unique surrogate identifier for each order fallout record in the Oracle Communications Order and Service Management (OSM) system. Primary key for the order_fallout data product.',
    `technician_id` BIGINT COMMENT 'Foreign key linking to workforce.technician. Business justification: Fallout resolution for field-related failures (site access, equipment issues, address problems) requires direct technician assignment for expedited recovery. Critical for operational escalation tracki',
    `corporate_account_id` BIGINT COMMENT 'Foreign key linking to enterprise.corporate_account. Business justification: Enterprise fallout tracking enables account-level quality metrics, TAM escalation workflows, customer experience dashboards for B2B customers, and proactive account management for at-risk enterprise r',
    `customer_account_id` BIGINT COMMENT 'Reference to the customer whose order has fallen out. Enables customer-level fallout analysis and SLA breach tracking in Salesforce CRM and BSS operations.',
    `fulfillment_order_id` BIGINT COMMENT 'Reference to the parent order that entered fallout state. Links this fallout record to the originating order in the Order Management domain.',
    `line_id` BIGINT COMMENT 'Foreign key linking to order.line. Business justification: A fallout record captures an order that entered ERROR state during orchestration. Fallouts are typically triggered by a failure on a specific line item (e.g., a particular service action fails). The f',
    `managed_service_id` BIGINT COMMENT 'Foreign key linking to enterprise.managed_service. Business justification: Order fallouts affecting managed service provisioning must be tracked against the managed service for SLA breach assessment, root cause analysis, and managed service reliability reporting. Enables man',
    `mnp_transaction_id` BIGINT COMMENT 'Foreign key linking to interconnect.mnp_transaction. Business justification: MNP fallout analysis and regulatory reporting: failed MNP ports (donor rejection, HLR failure) generate fallout records that must be linked to the mnp_transaction for root-cause analysis and regulator',
    `noc_incident_id` BIGINT COMMENT 'Reference to the corresponding ServiceNow ITSM incident ticket raised for this fallout event. Enables cross-system traceability between order management and IT service management workflows.',
    `offering_id` BIGINT COMMENT 'Foreign key linking to product.offering. Business justification: Offering-level fallout rate reporting: product managers need to identify which offerings have high order fallout rates for quality improvement. Direct FK enables offering-level fallout dashboards and ',
    `problem_record_id` BIGINT COMMENT 'Foreign key linking to assurance.problem_record. Business justification: Recurring order fallouts linked to known network problems for pattern analysis and permanent fix tracking. Enables proactive resolution of systemic provisioning issues.',
    `provisioning_order_id` BIGINT COMMENT 'Foreign key linking to service.provisioning_order. Business justification: Order fallouts frequently occur during provisioning execution. Linking fallout to the specific provisioning_order that failed enables OSS fallout resolution workflows, retry orchestration, and SLA bre',
    `ran_cell_id` BIGINT COMMENT 'Foreign key linking to network.ran_cell. Business justification: Mobile order fallouts caused by RAN cell issues (cell capacity exceeded, cell unavailable, radio parameter conflict) reference the specific cell. Fallout analysis and resolution for mobile provisionin',
    `team_id` BIGINT COMMENT 'Foreign key linking to workforce.team. Business justification: Fallout records are assigned to workforce teams for resolution. The existing assigned_team column is a plain-text denormalization of workforce.team. Telecom fallout management dashboards and team work',
    `spec_id` BIGINT COMMENT 'Reference to the product catalog entry for the product or service being ordered. Used to analyze fallout rates by product and identify catalog or provisioning configuration issues.',
    `subscriber_id` BIGINT COMMENT 'Foreign key linking to customer.subscriber. Business justification: Order fallout records track provisioning failures for a specific subscriber (SIM activation failure, MSISDN porting failure). The denormalized affected_msisdn field should be replaced by a proper FK t',
    `task_id` BIGINT COMMENT 'Reference to the specific orchestration task within the order workflow that triggered the fallout condition. Maps to the OSM task-level decomposition unit.',
    `transmission_link_id` BIGINT COMMENT 'Foreign key linking to network.transmission_link. Business justification: Order fallouts caused by transmission link issues (capacity unavailable, link down, provisioning failure) reference the specific link. Root cause analysis, fallout resolution workflows, and network-or',
    `affected_service_type` STRING COMMENT 'The type of telecommunications service affected by the fallout. Used to route fallout cases to the appropriate specialist team and apply service-specific resolution procedures. [ENUM-REF-CANDIDATE: MOBILE|BROADBAND|FIBER|IPTV|VOIP|ENTERPRISE_WAN|WHOLESALE — 7 candidates stripped; promote to reference product]',
    `auto_resolution_eligible` BOOLEAN COMMENT 'Indicates whether this fallout record is eligible for automated resolution without manual agent intervention, based on fallout category, retry history, and configured automation rules.',
    `channel` STRING COMMENT 'The sales or service channel through which the original order was submitted. Used to identify channel-specific fallout patterns and drive channel-level quality improvement initiatives. [ENUM-REF-CANDIDATE: ONLINE|RETAIL_STORE|CALL_CENTER|DEALER|SELF_SERVICE|B2B_PORTAL|API — 7 candidates stripped; promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this fallout record was first created in the data platform. Serves as the audit creation timestamp for data lineage and Silver layer ingestion tracking.',
    `customer_segment` STRING COMMENT 'The customer segment of the account associated with the fallen-out order. Denormalized for workqueue prioritization and segment-level SLA application without requiring a join to the customer domain.. Valid values are `CONSUMER|SMB|ENTERPRISE|WHOLESALE|MVNO`',
    `detected_timestamp` TIMESTAMP COMMENT 'The precise date and time when the order orchestration engine first detected and recorded the fallout condition. This is the principal business event timestamp for SLA measurement and aging calculations.',
    `error_code` STRING COMMENT 'System-generated error code returned by the failing downstream system or orchestration engine (e.g., OSM, HLR/HSS, provisioning platform). Used for automated pattern detection and root cause analysis.. Valid values are `^[A-Z]{2,6}-[0-9]{4,6}$`',
    `error_message` STRING COMMENT 'Full descriptive error message returned by the failing system at the time of fallout detection. Provides technical context for resolution agents and is used in automated error classification models.',
    `escalated_timestamp` TIMESTAMP COMMENT 'Date and time when this fallout record was most recently escalated to a higher resolution tier. Null if the record has never been escalated.',
    `escalation_level` STRING COMMENT 'Current escalation tier for this fallout record (0 = not escalated, 1 = team lead, 2 = manager, 3 = vendor/third-party). Incremented automatically when SLA thresholds are breached.',
    `failing_system` STRING COMMENT 'Name or identifier of the downstream OSS/BSS system that returned the error or failed to respond, causing the order to fall out. Examples: HLR, HSS, PROVISIONING_ENGINE, INVENTORY_MANAGER, CREDIT_SYSTEM, MNP_CLEARINGHOUSE.',
    `failing_system_transaction_reference` STRING COMMENT 'The transaction or correlation identifier returned by the failing downstream system. Enables cross-system tracing and incident correlation in ServiceNow ITSM and NOC tooling.',
    `fallout_category` STRING COMMENT 'High-level classification of the root cause that drove the order into fallout state. Drives workqueue routing and resolution team assignment. [ENUM-REF-CANDIDATE: VALIDATION_FAILURE|PROVISIONING_TIMEOUT|INVENTORY_SHORTAGE|DOWNSTREAM_SYSTEM_ERROR|CREDIT_CHECK_FAILURE|DUPLICATE_ORDER|MNP_PORT_FAILURE|FRAUD_HOLD|CAPACITY_EXHAUSTION|CONFIGURATION_ERROR — promote to reference product]. Valid values are `VALIDATION_FAILURE|PROVISIONING_TIMEOUT|INVENTORY_SHORTAGE|DOWNSTREAM_SYSTEM_ERROR|CREDIT_CHECK_FAILURE|DUPLICATE_ORDER`',
    `fallout_status` STRING COMMENT 'Current lifecycle state of the fallout record within the NOC/BSS operations workqueue. Drives SLA breach prevention workflows and management dashboards.. Valid values are `OPEN|IN_PROGRESS|RESOLVED|RESUBMITTED|CANCELLED|ESCALATED`',
    `last_retry_timestamp` TIMESTAMP COMMENT 'Date and time of the most recent automated or manual re-submission attempt for this fallout order. Used to enforce retry interval policies and prevent retry storms.',
    `max_retry_allowed` STRING COMMENT 'Maximum number of automated re-submission attempts permitted for this order type before mandatory escalation to manual resolution. Configured per order type and fallout category.',
    `priority` STRING COMMENT 'Operational priority assigned to this fallout record, determining workqueue position and escalation urgency. Derived from order type, customer segment, and SLA exposure at time of fallout detection.. Valid values are `CRITICAL|HIGH|MEDIUM|LOW`',
    `reference_number` STRING COMMENT 'Externally visible, human-readable reference number assigned to this fallout event by the OSS/BSS operations center. Used by NOC and BSS workqueue agents to track and communicate about the fallout case.. Valid values are `^FO-[0-9]{10}$`',
    `region_code` STRING COMMENT 'Geographic region code where the order was being fulfilled. Used for regional fallout rate analysis and to route cases to geographically appropriate field or provisioning teams.. Valid values are `^[A-Z]{2,6}$`',
    `resolution_action` STRING COMMENT 'Free-text description of the corrective action taken by the resolution agent to address the fallout root cause. Captured at resolution time and used for knowledge base and automation training.',
    `resolution_code` STRING COMMENT 'Standardized code categorizing the resolution action applied to close this fallout. Enables resolution pattern analysis and automation opportunity identification. [ENUM-REF-CANDIDATE: AUTO_RETRY_SUCCESS|MANUAL_CORRECTION|ORDER_CANCELLED|ORDER_MODIFIED|INVENTORY_ALLOCATED|SYSTEM_BYPASS|ESCALATED_TO_VENDOR|CUSTOMER_CONTACTED — promote to reference product]',
    `resolved_timestamp` TIMESTAMP COMMENT 'Date and time when the fallout record was marked as resolved in the operations workqueue. Used to calculate mean time to resolve (MTTR) for fallout SLA reporting.',
    `resubmission_outcome` STRING COMMENT 'Result of the order re-submission attempt after resolution action was applied. Indicates whether the order successfully completed fulfillment, failed again, is awaiting outcome, or was cancelled.. Valid values are `SUCCESS|FAILED|PENDING|CANCELLED`',
    `resubmission_timestamp` TIMESTAMP COMMENT 'Date and time when the order was resubmitted into the orchestration engine after resolution action was applied. Null if the order has not yet been resubmitted.',
    `retry_count` STRING COMMENT 'Number of automated or manual re-submission attempts made for this fallout order. Used to determine when to escalate from automated retry to manual intervention.',
    `root_cause_analysis` STRING COMMENT 'Structured root cause analysis narrative captured by the resolution agent or automated diagnostic engine. Documents the underlying cause beyond the error code for knowledge management and recurrence prevention.',
    `sla_breach_timestamp` TIMESTAMP COMMENT 'The date and time at which this fallout record will breach its applicable SLA if not resolved. Calculated at fallout detection time based on order type SLA thresholds. Null if no SLA applies.',
    `sla_breached` BOOLEAN COMMENT 'Indicates whether the SLA for this fallout record has been breached at the time of last update. True when current timestamp exceeds sla_breach_timestamp without resolution.',
    `source_system` STRING COMMENT 'Identifier of the operational system of record that originated this fallout record. Enables data lineage tracking and source-system-specific reconciliation in the Silver layer.. Valid values are `OSM|NETCRACKER|AMDOCS|COMVERSE|MANUAL`',
    `sub_category` STRING COMMENT 'Granular sub-classification within the fallout category providing additional specificity for root cause analysis. Examples: ADDRESS_VALIDATION_FAILED under VALIDATION_FAILURE, HLR_TIMEOUT under PROVISIONING_TIMEOUT, SIM_STOCK_DEPLETED under INVENTORY_SHORTAGE.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this fallout record was last modified in the data platform. Used for incremental data pipeline processing and audit trail maintenance.',
    `workflow_step_name` STRING COMMENT 'The name of the specific orchestration workflow step or process node within Oracle OSM that was executing when the fallout occurred. Enables precise identification of the failure point in the order decomposition graph.',
    `workflow_step_sequence` STRING COMMENT 'Numeric sequence position of the failing workflow step within the overall order orchestration process. Used to understand how far into fulfillment the order progressed before failing.',
    CONSTRAINT pk_fallout PRIMARY KEY(`fallout_id`)
) COMMENT 'Operational record capturing every order that has entered a FALLOUT or ERROR state during orchestration. Stores the fallout category (validation failure, provisioning timeout, inventory shortage, downstream system error), affected order and task references, fallout detection timestamp, assigned resolution team, resolution action taken, and re-submission outcome. Drives NOC and BSS operations center workqueues for manual intervention and SLA breach prevention.';

CREATE OR REPLACE TABLE `telecommunication_ecm`.`order`.`provisioning_request` (
    `provisioning_request_id` BIGINT COMMENT 'Unique surrogate identifier for the provisioning request record in the Silver Layer lakehouse. Primary key for this entity. Role: TRANSACTION_HEADER.',
    `addon_id` BIGINT COMMENT 'Foreign key linking to product.addon. Business justification: Add-on provisioning: when provisioning an add-on (e.g., international roaming, VoLTE, extra data bolt-on), the provisioning request must reference the specific addon for correct network configuration ',
    `corporate_account_id` BIGINT COMMENT 'Foreign key linking to enterprise.corporate_account. Business justification: Provisioning requests for enterprise services need corporate account context for proper system routing, account-specific configuration templates, and enterprise provisioning workflow orchestration.',
    `cpe_asset_id` BIGINT COMMENT 'Foreign key linking to inventory.cpe_asset. Business justification: Broadband provisioning requests configure specific CPE assets (APN, QoS, bandwidth profile). The provisioning system must directly reference the physical CPE being configured without joining through o',
    `customer_account_id` BIGINT COMMENT 'Reference to the customer on whose behalf this provisioning request is being executed. Enables customer-centric analytics and SLA tracking across the provisioning lifecycle.',
    `fulfillment_order_id` BIGINT COMMENT 'Reference to the parent order in the order management domain that triggered this provisioning request. Links the provisioning instruction back to the originating customer order for end-to-end traceability. Satisfies TRANSACTION_HEADER PARTY_REFERENCE (via order → customer chain).',
    `ip_address_pool_id` BIGINT COMMENT 'Foreign key linking to inventory.ip_address_pool. Business justification: Broadband provisioning requests allocate IP addresses from specific pools. The provisioning system references the pool for allocation and tracks utilization. ip_address_assigned on provisioning_reques',
    `lawful_intercept_order_id` BIGINT COMMENT 'Foreign key linking to compliance.lawful_intercept_order. Business justification: Lawful intercept activation requires specific provisioning actions on network elements. Linking provisioning_request to lawful_intercept_order enables chain-of-custody verification that intercept prov',
    `line_id` BIGINT COMMENT 'Foreign key linking to order.line. Business justification: A provisioning_request is a downstream provisioning instruction generated by OSM from a specific order line. One line can generate one or more provisioning requests (e.g., SIM provisioning, HLR activa',
    `managed_service_id` BIGINT COMMENT 'Foreign key linking to enterprise.managed_service. Business justification: Provisioning requests target specific managed service instances for configuration updates, capacity changes, service modifications, or feature activations. Essential for managed service lifecycle mana',
    `mnp_transaction_id` BIGINT COMMENT 'Foreign key linking to interconnect.mnp_transaction. Business justification: MNP provisioning execution: provisioning_requests for HLR/HSS updates and routing number assignments are generated as part of MNP transaction execution. Linking enables end-to-end MNP provisioning aud',
    `msisdn_range_id` BIGINT COMMENT 'Foreign key linking to inventory.msisdn_range. Business justification: Mobile provisioning requests allocate MSISDNs from specific number ranges. The provisioning system references the range for number assignment during new activations and MNP. msisdn on provisioning_req',
    `mvno_profile_id` BIGINT COMMENT 'Foreign key linking to partner.mvno_profile. Business justification: Provisioning requests for MVNO subscribers must reference the MVNO profile to obtain IMSI range, APN configuration, HLR/HSS provisioning flags, and QoS parameters. Telecom provisioning systems read MV',
    `element_id` BIGINT COMMENT 'Foreign key linking to network.element. Business justification: Provisioning requests target specific network elements for service activation (HLR/HSS for mobile, BRAS for broadband). Essential for OSS/BSS integration, tracking provisioning status per network elem',
    `offering_id` BIGINT COMMENT 'Foreign key linking to product.offering. Business justification: Provisioning parameter lookup by offering: provisioning systems require direct offering reference to retrieve service parameters, QoS profiles, and APN configurations without traversing fulfillment_or',
    `ont_asset_id` BIGINT COMMENT 'Foreign key linking to inventory.ont_asset. Business justification: Fiber provisioning requests activate specific ONT devices on GPON network. Real business need: OLT port binding, bandwidth profile assignment, optical power monitoring, device firmware management. Exi',
    `problem_record_id` BIGINT COMMENT 'Foreign key linking to assurance.problem_record. Business justification: Systemic provisioning failures are escalated to problem records for root cause investigation in ITIL-based telecom operations. Linking provisioning_request to problem_record enables identification of ',
    `qos_profile_id` BIGINT COMMENT 'Foreign key linking to network.network_qos_profile. Business justification: Provisioning requests carry a qos_profile_code (denormalized plain attribute) identifying the QoS profile to apply. Replacing with a proper FK to network_qos_profile enforces referential integrity and',
    `ran_cell_id` BIGINT COMMENT 'Foreign key linking to network.ran_cell. Business justification: Mobile provisioning requests (IMSI/MSISDN activation, SIM provisioning) target a specific RAN cell. Mobile OSS provisioning workflows require cell-level targeting for capacity validation and radio par',
    `sim_stock_id` BIGINT COMMENT 'Foreign key linking to inventory.sim_stock. Business justification: Provisioning requests configure specific SIM cards in network elements (HLR/HSS/UDM). Real business need: network activation audit, provisioning failure resolution, SIM lifecycle state synchronization',
    `site_id` BIGINT COMMENT 'Foreign key linking to enterprise.enterprise_site. Business justification: Provisioning requests for enterprise services are executed at specific physical sites. Direct link enables site-level provisioning status dashboards, installation scheduling, and infrastructure readin',
    `slice_id` BIGINT COMMENT 'Foreign key linking to network.slice. Business justification: 5G slice provisioning requests target a specific network slice for instantiation, modification, or termination. The provisioning system must reference the slice to send correct parameters to the NSSF ',
    `subscriber_id` BIGINT COMMENT 'Foreign key linking to customer.subscriber. Business justification: Provisioning requests execute subscriber-level service changes (SIM activation, MSISDN porting, VoLTE enablement). Telecom provisioning systems are subscriber-centric; linking provisioning_request to ',
    `svc_instance_id` BIGINT COMMENT 'Reference to the service instance being provisioned, modified, or deactivated. Links to the service domain to identify the specific service (e.g., mobile line, broadband subscription, IPTV package) subject to this provisioning action.',
    `task_id` BIGINT COMMENT 'Foreign key linking to order.task. Business justification: A provisioning_request is dispatched by OSM as a result of a granular work task. The task orchestrates the provisioning action and the provisioning_request is the downstream instruction sent to OSS sy',
    `transmission_link_id` BIGINT COMMENT 'Foreign key linking to network.transmission_link. Business justification: Fixed broadband and leased-line provisioning requests target a specific transmission link for activation or modification. Provisioning teams and OSS systems must know which transmission link is being ',
    `acknowledgement_timestamp` TIMESTAMP COMMENT 'The date and time when the target OSS system acknowledged receipt of the provisioning instruction. Used to calculate dispatch-to-acknowledgement latency and detect timeout conditions against SLA thresholds.',
    `apn` STRING COMMENT 'The Access Point Name (APN) configured for the mobile data service being provisioned. Determines the packet data network gateway and internet access policy for the subscriber. Applicable for mobile broadband and IoT service provisioning.',
    `bandwidth_profile_code` STRING COMMENT 'Code identifying the bandwidth profile (upstream/downstream speed tier) to be applied to the service. Maps to a predefined bandwidth template in the OLT, DSLAM, or BNG configuration. Examples: 100M_FTTH, 1G_FTTH, 50M_ADSL.',
    `channel` STRING COMMENT 'The originating channel through which the customer order that triggered this provisioning request was placed. ONLINE: self-service web/app; STORE: retail point of sale; CALL_CENTER: agent-assisted; PARTNER: MVNO or wholesale partner; FIELD_TECH: field technician dispatch; AUTOMATED: system-triggered (e.g., auto-renewal, policy enforcement).. Valid values are `ONLINE|STORE|CALL_CENTER|PARTNER|FIELD_TECH|AUTOMATED`',
    `completion_timestamp` TIMESTAMP COMMENT 'The date and time when the target OSS system reported final completion (success or failure) of the provisioning action. Used to measure end-to-end provisioning cycle time and SLA compliance.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this provisioning request record was first created in the OSM system. Serves as the audit creation timestamp for data lineage and compliance purposes. Satisfies TRANSACTION_HEADER RECORD_AUDIT_CREATED category.',
    `data_classification` STRING COMMENT 'Data governance classification level for this provisioning request record, indicating sensitivity and access control requirements. Aligned with the enterprise data classification policy: restricted (highest sensitivity), confidential, internal, public.. Valid values are `restricted|confidential|internal|public`',
    `dispatch_timestamp` TIMESTAMP COMMENT 'The date and time (ISO 8601 with timezone offset) when the provisioning instruction was dispatched from Oracle Communications OSM to the target OSS system. Represents the principal real-world business event time. Satisfies TRANSACTION_HEADER BUSINESS_EVENT_TIMESTAMP category.',
    `failure_reason_code` STRING COMMENT 'Standardized error or failure reason code returned by the target OSS system when provisioning_outcome is FAILURE or TIMEOUT. Used for fault management, root cause analysis, and automated retry logic. Examples: RESOURCE_UNAVAILABLE, INVALID_PARAMETER, SYSTEM_UNREACHABLE, DUPLICATE_REQUEST.',
    `failure_reason_description` STRING COMMENT 'Human-readable description of the failure reason as returned by the target OSS system or populated by the OSM orchestration layer. Provides operational context for NOC engineers and support teams investigating provisioning failures.',
    `iccid` STRING COMMENT 'The Integrated Circuit Card Identifier (ICCID) — the unique serial number of the SIM or eSIM card — associated with this provisioning request. Used to link the provisioning action to the physical or embedded SIM being activated.. Valid values are `^[0-9]{18,22}$`',
    `imsi` STRING COMMENT 'The International Mobile Subscriber Identity (IMSI) — a unique 15-digit identifier stored on the SIM/eSIM — being provisioned in the HLR/HSS/UDM. Applicable for mobile service activations and MNP port-in operations. Classified as restricted PII as it uniquely identifies a subscriber.. Valid values are `^[0-9]{15}$`',
    `is_rollback_required` BOOLEAN COMMENT 'Indicates whether a rollback of previously applied provisioning changes is required due to a downstream failure in a multi-step orchestration workflow. When TRUE, the OSM compensation workflow is triggered to reverse partial provisioning actions.',
    `last_retry_timestamp` TIMESTAMP COMMENT 'The date and time of the most recent retry attempt for this provisioning request. Used in conjunction with retry_count to calculate retry intervals and enforce exponential backoff policies.',
    `max_retry_limit` STRING COMMENT 'The maximum number of retry attempts configured for this provisioning request before it is escalated or marked as permanently failed. Derived from the service type SLA policy at the time of request creation.',
    `mnp_donor_operator_code` STRING COMMENT 'For Mobile Number Portability (MNP) PORT_IN provisioning actions, the network operator code of the donor (losing) operator from whom the number is being ported. Populated per GSMA PRD IR.26 and national MNP regulatory requirements.',
    `mnp_port_date` DATE COMMENT 'The scheduled or actual date on which the Mobile Number Portability (MNP) port-in or port-out is to be executed. Applicable only when provisioning_action is PORT_IN or PORT_OUT. Governed by national MNP regulatory timelines.',
    `network_region_code` STRING COMMENT 'Code identifying the geographic network region or Point of Presence (POP) within which the provisioning action is being executed. Used for regional capacity planning, NOC routing, and geographic SLA analysis.',
    `ont_serial_number` STRING COMMENT 'Serial number of the Optical Network Terminal (ONT) / Customer Premises Equipment (CPE) device being provisioned on the GPON OLT for FTTH fiber services. Used to bind the physical device to the subscribers service profile in the OLT configuration.',
    `priority_level` STRING COMMENT 'Business priority assigned to this provisioning request, determining queue position and resource allocation in the OSM orchestration engine. CRITICAL: emergency/regulatory-mandated; HIGH: premium customer or SLA-sensitive; MEDIUM: standard commercial; LOW: batch/bulk provisioning.. Valid values are `CRITICAL|HIGH|MEDIUM|LOW`',
    `provisioning_action` STRING COMMENT 'The type of provisioning operation to be performed on the target OSS system. ACTIVATE: new service activation; MODIFY: change of service parameters; DEACTIVATE: service disconnection; SUSPEND: temporary service suspension; RESUME: reinstatement after suspension; PORT_IN: Mobile Number Portability (MNP) inbound port; PORT_OUT: MNP outbound port. [ENUM-REF-CANDIDATE: ACTIVATE|MODIFY|DEACTIVATE|SUSPEND|RESUME|PORT_IN|PORT_OUT — 7 candidates stripped; promote to reference product]',
    `provisioning_outcome` STRING COMMENT 'Final result of the provisioning execution as reported by the target OSS system. SUCCESS: service fully activated/modified/deactivated as requested; FAILURE: provisioning could not be completed; TIMEOUT: target system did not respond within the configured timeout window; PARTIAL: some but not all service components were provisioned (e.g., multi-component service). Satisfies TRANSACTION_HEADER QUANTITATIVE_RESULT category for non-monetary transactions.. Valid values are `SUCCESS|FAILURE|TIMEOUT|PARTIAL`',
    `request_number` STRING COMMENT 'Externally-known, human-readable business identifier for the provisioning request as generated by Oracle Communications OSM (e.g., PROV-2024-0001234). Used for cross-system traceability across OSS/BSS platforms. Satisfies TRANSACTION_HEADER BUSINESS_IDENTIFIER category.',
    `request_status` STRING COMMENT 'Current lifecycle state of the provisioning request. PENDING: awaiting dispatch; DISPATCHED: sent to target OSS system; IN_PROGRESS: being processed by target system; SUCCESS: provisioning completed successfully; FAILURE: provisioning failed; TIMEOUT: no acknowledgement received within SLA window; CANCELLED: request withdrawn before execution. Satisfies TRANSACTION_HEADER LIFECYCLE_STATUS category. [ENUM-REF-CANDIDATE: PENDING|DISPATCHED|IN_PROGRESS|SUCCESS|FAILURE|TIMEOUT|CANCELLED — 7 candidates stripped; promote to reference product]',
    `retry_count` STRING COMMENT 'Number of times this provisioning request has been retried after an initial failure or timeout. Used to enforce maximum retry policies, trigger escalation workflows, and analyze systemic provisioning issues.',
    `rollback_timestamp` TIMESTAMP COMMENT 'The date and time when the rollback compensation action was executed for this provisioning request. Populated only when is_rollback_required is TRUE and the rollback has been completed.',
    `scheduled_activation_date` DATE COMMENT 'The date on which the service activation or modification is scheduled to take effect, as agreed with the customer or mandated by the order. May differ from dispatch_timestamp for future-dated provisioning requests.',
    `service_parameters_payload` STRING COMMENT 'Serialized (JSON or XML) payload containing the service-specific configuration parameters dispatched to the target OSS system. For mobile services: MSISDN, IMSI, APN, QoS profile; for FTTH/GPON: ONT serial number, VLAN ID, bandwidth profile; for IMS: SIP URI, codec list. Stored as STRING to accommodate heterogeneous service types.',
    `service_type` STRING COMMENT 'Classification of the telecommunications service being provisioned. Determines the provisioning workflow, target OSS system, and service parameters payload structure. Examples: MOBILE (LTE/5G NR), BROADBAND (DSL/cable), FIBER_FTTH (Gigabit Passive Optical Network), VoIP, IPTV, FIXED_LINE, SD-WAN, MPLS. [ENUM-REF-CANDIDATE: MOBILE|BROADBAND|FIBER_FTTH|VOIP|IPTV|FIXED_LINE|SD_WAN|MPLS — promote to reference product]',
    `sla_breach_flag` BOOLEAN COMMENT 'Indicates whether this provisioning request breached its SLA target duration. Set to TRUE when the actual provisioning duration exceeded sla_target_duration_seconds. Used for SLA reporting, penalty calculations, and operational performance management.',
    `sla_target_duration_seconds` STRING COMMENT 'The contracted Service Level Agreement (SLA) target duration in seconds within which this provisioning request must be completed end-to-end. Used for SLA compliance monitoring and breach detection in NOC dashboards.',
    `source_system_code` STRING COMMENT 'Code identifying the upstream BSS/OSS system that originated this provisioning request. OSM: Oracle Communications Order and Service Management; NETCRACKER: Netcracker OSS/BSS Suite; AMDOCS: Amdocs Revenue Management; COMVERSE: Comverse ONE prepaid charging; MANUAL: manually created by NOC operator.. Valid values are `OSM|NETCRACKER|AMDOCS|COMVERSE|MANUAL`',
    `target_system_code` STRING COMMENT 'Code identifying the downstream OSS system to which this provisioning instruction is dispatched. Valid values include: HLR (Home Location Register), HSS (Home Subscriber Server), UDM (Unified Data Management), IMS (IP Multimedia Subsystem), GPON_OLT (Gigabit Passive Optical Network Optical Line Terminal), IPAM (IP Address Management), DSLAM (Digital Subscriber Line Access Multiplexer), RAN (Radio Access Network), PCRF (Policy and Charging Rules Function), PCF (Policy Control Function). [ENUM-REF-CANDIDATE: HLR|HSS|UDM|IMS|GPON_OLT|IPAM|DSLAM|RAN|PCRF|PCF — promote to reference product]',
    `target_system_instance_reference` STRING COMMENT 'Identifier of the specific system instance or node within the target OSS system (e.g., HSS cluster node ID, OLT shelf/port identifier) to which the provisioning command is routed. Supports multi-node environments and geo-redundant deployments.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this provisioning request record was last modified. Tracks state transitions, retry events, and status updates for audit trail and data lineage. Satisfies TRANSACTION_HEADER RECORD_AUDIT_UPDATED category.',
    `vlan_number` STRING COMMENT 'The Virtual LAN (VLAN) ID assigned to the subscribers service on the GPON OLT or DSLAM for traffic segregation and QoS enforcement. Applicable for FTTH and broadband service provisioning.',
    CONSTRAINT pk_provisioning_request PRIMARY KEY(`provisioning_request_id`)
) COMMENT 'Downstream provisioning instruction record generated by OSM and dispatched to OSS systems (HLR/HSS, UDM, IMS, GPON OLT, IP address management, DSLAM) to activate, modify, or deactivate a service on the network. Captures target system identifier, provisioning action, service parameters payload, dispatch timestamp, acknowledgement timestamp, provisioning outcome (SUCCESS, FAILURE, TIMEOUT), and retry history. Bridges the order domain to the service and network domains.';

CREATE OR REPLACE TABLE `telecommunication_ecm`.`order`.`service_qualification` (
    `service_qualification_id` BIGINT COMMENT 'Unique surrogate identifier for the service qualification record. Primary key for the service_qualification data product in the order domain Silver layer.',
    `address_id` BIGINT COMMENT 'Reference to the customer premises or installation address record against which the network eligibility check is performed. Resolves to the address master in Netcracker Resource Inventory or the geographic address repository.',
    `corporate_account_id` BIGINT COMMENT 'Foreign key linking to enterprise.corporate_account. Business justification: Enterprise service qualification requests require corporate account linkage for credit validation, contract eligibility checks, account-level service portfolio management, and pre-sales feasibility an',
    `customer_account_id` BIGINT COMMENT 'Reference to the customer (prospect or existing subscriber) on whose behalf the service qualification is being performed. Links to the customer master in Salesforce CRM / Netcracker BSS. Serves as the PARTY_REFERENCE for this transaction.',
    `fiber_cable_id` BIGINT COMMENT 'Foreign key linking to inventory.fiber_cable. Business justification: Fiber service qualification checks whether fiber cable infrastructure reaches the customer address. The qualification process references the specific cable segment for availability and capacity assess',
    `fulfillment_order_id` BIGINT COMMENT 'Reference to the parent order or pre-order request that triggered this service qualification check in Oracle Communications Order and Service Management. Null if the qualification was initiated as a standalone eligibility check outside of a formal order.',
    `managed_service_id` BIGINT COMMENT 'Foreign key linking to enterprise.managed_service. Business justification: Re-qualification or upgrade of an existing managed service requires linking the qualification record to the managed service being assessed. Enables managed service upgrade eligibility reporting and te',
    `mvno_profile_id` BIGINT COMMENT 'Foreign key linking to partner.mvno_profile. Business justification: MVNO service qualifications must check MVNO-specific constraints: subscriber capacity limits, IMSI/MSISDN range availability, spectrum access rights, and technical capabilities - required for MVNO sub',
    `olt_asset_id` BIGINT COMMENT 'Foreign key linking to inventory.olt_asset. Business justification: Fiber service qualification checks OLT port capacity and operational status before committing to a fiber service offer. Direct reference to the serving OLT asset is required for capacity management, q',
    `offering_id` BIGINT COMMENT 'Reference to the specific product offering in the Netcracker Product Catalog for which eligibility is being assessed. Drives which product offers are surfaced to the sales agent or digital channel upon a positive qualification outcome.',
    `ran_cell_id` BIGINT COMMENT 'Foreign key linking to network.ran_cell. Business justification: Mobile service qualification identifies serving cell, measures signal strength, and validates capacity availability. Critical pre-sale process for determining mobile service eligibility and setting cu',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: service_qualification.broadband_subsidy_eligible and regulatory_zone_code indicate qualifications governed by regulatory obligations (universal service, broadband subsidy programs). Linking to the gov',
    `sdwan_topology_id` BIGINT COMMENT 'Foreign key linking to enterprise.sdwan_topology. Business justification: Network infrastructure readiness qualification for SD-WAN topology deployment (bandwidth availability, latency assessment, underlay transport options) must reference the SD-WAN topology. Enables topol',
    `site_id` BIGINT COMMENT 'Foreign key linking to enterprise.enterprise_site. Business justification: Service qualification for enterprise customers is performed against a specific physical site. Site-level qualification drives field survey scheduling, infrastructure readiness assessment, and installa',
    `slice_id` BIGINT COMMENT 'Foreign key linking to network.slice. Business justification: Service qualification for 5G slice services checks whether a specific slice type and configuration is available in the coverage area. Pre-sales qualification for enterprise slice offerings must refere',
    `technician_id` BIGINT COMMENT 'Foreign key linking to workforce.technician. Business justification: When field_survey_required=true on a service qualification, a technician is dispatched for a pre-sales site survey. Telecom pre-sales operations track which technician conducted the survey to link sur',
    `transmission_link_id` BIGINT COMMENT 'Foreign key linking to network.transmission_link. Business justification: Fixed broadband and leased-line service qualification checks capacity and availability on a specific transmission link. Pre-sales and order entry teams query transmission link status and utilization t',
    `address_line_1` STRING COMMENT 'Primary street address line of the customer premises being qualified for service. Captured at qualification time as a point-in-time snapshot to avoid dependency on address master changes post-qualification.',
    `address_line_2` STRING COMMENT 'Secondary address line (apartment, suite, floor, unit number) of the customer premises being qualified. Nullable for single-dwelling units.',
    `available_technology_options` STRING COMMENT 'Pipe-delimited list of all access technologies technically available at the qualified address (e.g., FTTH|LTE|5G_NR). Enables the sales system to present all eligible product offers, not just the primary requested technology. Sourced from Netcracker Resource Inventory network coverage data.',
    `broadband_subsidy_eligible` BOOLEAN COMMENT 'Indicates whether the service address qualifies for government broadband subsidy programs (e.g., FCC Affordable Connectivity Program (ACP), NTIA BEAD, UK Gigabit Voucher Scheme). Determined based on regulatory_zone_code and address-level coverage data. Relevant for compliance reporting to FCC, NTIA, and Ofcom.',
    `city` STRING COMMENT 'City or municipality of the service installation address. Used for geographic coverage reporting and network rollout planning analytics.',
    `constraint_description` STRING COMMENT 'Free-text description of any technical or operational constraints identified during the qualification check when the outcome is ELIGIBLE_WITH_CONSTRAINTS. Examples: Maximum speed limited to 100 Mbps due to copper loop length, CPE upgrade required, Shared GPON port — peak-hour congestion possible. Null when outcome is ELIGIBLE or NOT_ELIGIBLE.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 three-letter country code of the service installation address (e.g., USA, GBR, DEU). Required for multi-country operators and regulatory jurisdiction determination.. Valid values are `^[A-Z]{3}$`',
    `cpe_required` BOOLEAN COMMENT 'Indicates whether a Customer Premises Equipment (CPE) installation or upgrade is required to deliver the requested service at the qualified address. True: CPE installation/upgrade is mandatory; False: existing CPE is compatible or no CPE is needed.',
    `cpe_type` STRING COMMENT 'Type of CPE required for service delivery at the qualified address. ONT (Optical Network Terminal) for FTTH/GPON; ROUTER for broadband; MODEM for DSL; GATEWAY for combined modem/router; OUTDOOR_UNIT/INDOOR_UNIT for fixed wireless. Null when cpe_required is False.. Valid values are `ONT|ROUTER|MODEM|GATEWAY|OUTDOOR_UNIT|INDOOR_UNIT`',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this service qualification record was first persisted in the Silver layer data product. Populated by the ingestion pipeline from Oracle OSM source system.',
    `estimated_installation_lead_time_days` STRING COMMENT 'Estimated number of calendar days from order confirmation to service activation at the qualified address. Derived from field workforce availability (Granite WFM), infrastructure readiness, and network node capacity. Displayed to customers during the ordering flow to set delivery expectations.',
    `estimated_latency_ms` DECIMAL(18,2) COMMENT 'Estimated round-trip network latency in milliseconds at the qualified address for the requested service type. Relevant for QoS-sensitive product offers (VoLTE, gaming, enterprise SD-WAN) and SLA eligibility determination.',
    `field_survey_required` BOOLEAN COMMENT 'Indicates whether a physical field survey by a Telecommunication technician is required before service can be provisioned at this address. True when infrastructure readiness is PARTIAL or NOT_READY, or when the qualification engine cannot determine feasibility remotely. Triggers a field dispatch work order in Granite WFM.',
    `ineligibility_reason_code` STRING COMMENT 'Standardized reason code explaining why the address is NOT_ELIGIBLE for the requested service. NO_COVERAGE: outside network footprint; CAPACITY_EXHAUSTED: node at full capacity; INFRASTRUCTURE_NOT_BUILT: planned but not yet deployed; ADDRESS_NOT_FOUND: address could not be geocoded or matched; TECHNICAL_BARRIER: physical impediment; REGULATORY_RESTRICTION: regulatory constraint. Null when outcome is ELIGIBLE or ELIGIBLE_WITH_CONSTRAINTS.. Valid values are `NO_COVERAGE|CAPACITY_EXHAUSTED|INFRASTRUCTURE_NOT_BUILT|ADDRESS_NOT_FOUND|TECHNICAL_BARRIER|REGULATORY_RESTRICTION`',
    `infrastructure_readiness` STRING COMMENT 'Indicates the physical network infrastructure readiness at or near the service address. READY: full infrastructure in place; PARTIAL: partial build-out, service possible with constraints; NOT_READY: no infrastructure present; UNDER_CONSTRUCTION: active network build in progress with a planned completion date.. Valid values are `READY|PARTIAL|NOT_READY|UNDER_CONSTRUCTION`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording the most recent update to this service qualification record in the Silver layer. Updated on any status change, outcome determination, or data correction.',
    `latitude` DECIMAL(18,2) COMMENT 'Geographic latitude coordinate (WGS84 decimal degrees) of the service installation point. Used for precise network coverage mapping, field dispatch routing via Granite WFM, and FCC broadband location fabric matching.',
    `longitude` DECIMAL(18,2) COMMENT 'Geographic longitude coordinate (WGS84 decimal degrees) of the service installation point. Used in conjunction with latitude for geospatial coverage analysis and network node proximity calculations.',
    `max_download_speed_mbps` DECIMAL(18,2) COMMENT 'Maximum technically achievable downstream bandwidth in Megabits per second (Mbps) at the qualified address, as determined by the network qualification engine based on distance to node, line quality, and technology capability. Drives product tier eligibility in the sales flow.',
    `max_upload_speed_mbps` DECIMAL(18,2) COMMENT 'Maximum technically achievable upstream bandwidth in Megabits per second (Mbps) at the qualified address. Critical for symmetric service offerings (FTTH/GPON) and business-grade SLA commitments.',
    `mnp_applicable` BOOLEAN COMMENT 'Indicates whether Mobile Number Portability (MNP) is applicable to this service qualification, relevant for mobile service types (LTE, 5G NR) where the customer intends to port an existing number. True triggers MNP eligibility checks in the downstream order flow.',
    `notes` STRING COMMENT 'Free-text notes or remarks added by the sales agent, network engineer, or automated qualification engine to provide additional context about the qualification result. May include special instructions for the field team, customer-specific considerations, or escalation notes.',
    `postal_code` STRING COMMENT 'Postal or ZIP code of the service installation address. Key dimension for network coverage gap analysis, FCC broadband availability reporting, and NTIA compliance.. Valid values are `^[A-Z0-9 -]{3,10}$`',
    `qualification_channel` STRING COMMENT 'The sales or service channel through which the qualification request was initiated. ONLINE: digital self-service portal; RETAIL_STORE: in-store agent; CALL_CENTER: inbound/outbound agent via Salesforce CRM; PARTNER_API: wholesale or MVNO partner API; FIELD_AGENT: mobile field sales; SELF_SERVICE: automated IVR or chatbot.. Valid values are `ONLINE|RETAIL_STORE|CALL_CENTER|PARTNER_API|FIELD_AGENT|SELF_SERVICE`',
    `qualification_completed_timestamp` TIMESTAMP COMMENT 'The date and time when the qualification check was fully resolved and an outcome was determined. Null if the qualification is still IN_PROGRESS or was CANCELLED before completion.',
    `qualification_expiry_date` DATE COMMENT 'The date after which the qualification result is considered stale and must be re-evaluated before an order can be placed. Network conditions, capacity, and infrastructure status can change; this date enforces re-qualification for orders placed after a defined validity window (typically 30–90 days).',
    `qualification_outcome` STRING COMMENT 'Business result of the pre-order service qualification check. ELIGIBLE: the address/location can receive the requested service without restriction; NOT_ELIGIBLE: service cannot be delivered to this location; ELIGIBLE_WITH_CONSTRAINTS: service is technically feasible but subject to limitations (e.g., reduced bandwidth, extended lead time, CPE upgrade required).. Valid values are `ELIGIBLE|NOT_ELIGIBLE|ELIGIBLE_WITH_CONSTRAINTS`',
    `qualification_reference_number` STRING COMMENT 'Externally visible, human-readable reference number assigned to the qualification request by Oracle Communications Order and Service Management (OSM). Used by sales agents and customers to track the qualification check.',
    `qualification_request_timestamp` TIMESTAMP COMMENT 'The exact date and time (ISO 8601 with timezone offset) when the qualification request was submitted by the sales or ordering system. This is the principal business event timestamp for this transaction.',
    `qualification_source_system` STRING COMMENT 'The originating operational system that submitted the qualification request. OSM: Oracle Communications Order and Service Management; SALESFORCE: Salesforce CRM; NETCRACKER: Netcracker OSS/BSS Suite; PARTNER_PORTAL: wholesale/MVNO partner portal; SELF_SERVICE_PORTAL: customer-facing digital portal. Used for data lineage and system-of-record traceability.. Valid values are `OSM|SALESFORCE|NETCRACKER|PARTNER_PORTAL|SELF_SERVICE_PORTAL`',
    `qualification_status` STRING COMMENT 'Current lifecycle state of the qualification request workflow within Oracle OSM. IN_PROGRESS: check is being executed; COMPLETED: outcome determined; FAILED: system error prevented completion; CANCELLED: request withdrawn before completion.. Valid values are `IN_PROGRESS|COMPLETED|FAILED|CANCELLED`',
    `regulatory_zone_code` STRING COMMENT 'Regulatory or geographic zone code assigned to the service address, used to determine applicable regulatory obligations (e.g., FCC Universal Service Fund (USF) eligible area, NTIA BEAD-eligible zone, Ofcom Universal Service Obligation (USO) area, BEREC regulated zone). Drives compliance reporting and subsidy eligibility.',
    `requalification_required` BOOLEAN COMMENT 'Indicates whether this qualification result has been flagged as requiring re-execution before an order can proceed. Set to True when the qualification_expiry_date has passed, when network topology changes have occurred in the serving area, or when the customer requests a different service type.',
    `requested_service_type` STRING COMMENT 'The access technology or service type for which eligibility is being assessed. Values align with the network technologies offered by Telecommunication: FTTH (Fiber to the Home), GPON (Gigabit Passive Optical Network), LTE (Long-Term Evolution), 5G NR (5G New Radio), ADSL, VDSL, FTTB (Fiber to the Building), FTTC (Fiber to the Cabinet), FIXED_WIRELESS. [ENUM-REF-CANDIDATE: FTTH|GPON|LTE|5G_NR|ADSL|VDSL|FTTB|FTTC|FIXED_WIRELESS — promote to reference product]',
    `signal_strength_dbm` DECIMAL(18,2) COMMENT 'Measured or predicted radio signal strength in dBm at the qualified address for wireless service types (LTE, 5G NR, Fixed Wireless). Null for wireline technologies. Sourced from Ericsson Network Manager RAN coverage data or Nokia NetAct RF planning tools.',
    `state_province` STRING COMMENT 'State, province, or region of the service installation address. Used for regulatory jurisdiction mapping (FCC, NTIA) and regional network coverage analytics.',
    `survey_scheduled_date` DATE COMMENT 'The calendar date on which the field survey is scheduled to be conducted at the customer premises, when field_survey_required is True. Populated by Granite WFM upon technician dispatch scheduling. Null when no survey is required.',
    CONSTRAINT pk_service_qualification PRIMARY KEY(`service_qualification_id`)
) COMMENT 'Pre-order service qualification check record determining whether a customer address or network location is eligible for a requested service (FTTH, GPON, LTE, 5G NR, ADSL, VDSL). Captures qualification request timestamp, customer address reference, requested service type, qualification outcome (ELIGIBLE, NOT_ELIGIBLE, ELIGIBLE_WITH_CONSTRAINTS), available technology options, maximum achievable bandwidth, estimated installation lead time, and network node reference. Drives product offer eligibility in the sales and ordering flow.';

CREATE OR REPLACE TABLE `telecommunication_ecm`.`order`.`appointment` (
    `appointment_id` BIGINT COMMENT 'Unique surrogate identifier for the field technician appointment record within the order fulfillment domain. Primary key for the appointment data product.',
    `customer_account_id` BIGINT COMMENT 'Reference to the customer account for whom the on-site appointment is being conducted. Enables customer-centric reporting and SLA tracking.',
    `customer_contact_id` BIGINT COMMENT 'Foreign key linking to customer.customer_contact. Business justification: Field appointments require a specific authorized contact at the premises for access and sign-off. The denormalized customer_contact_name and customer_contact_phone fields should be replaced by a prope',
    `depot_id` BIGINT COMMENT 'Foreign key linking to workforce.depot. Business justification: Appointments are scheduled from depots managing technician territories and service zones. Essential for capacity planning, technician assignment optimization, and tracking which facility supports cust',
    `device_model_id` BIGINT COMMENT 'Foreign key linking to product.device_model. Business justification: Field technician appointment preparation: technicians need the specific device model to bring correct equipment, firmware, and installation tools. cpe_model is a denormalized device model reference; r',
    `fulfillment_order_id` BIGINT COMMENT 'Reference to the parent fulfillment order that triggered this appointment. Links the appointment to the end-to-end order lifecycle managed in Oracle Communications Order and Service Management (OSM).',
    `cpe_asset_id` BIGINT COMMENT 'Foreign key linking to inventory.cpe_asset. Business justification: Field appointments install or swap specific CPE devices at customer premises. Real business need: technician dispatch with correct device, installation verification, asset tracking, warranty activatio',
    `managed_service_id` BIGINT COMMENT 'Foreign key linking to enterprise.managed_service. Business justification: Field appointments for managed service installations, maintenance windows, and fault resolution must be linked to the managed service for SLA measurement, change window compliance, and managed service',
    `network_equipment_id` BIGINT COMMENT 'Foreign key linking to inventory.network_equipment. Business justification: Appointments for network equipment installation, maintenance, or replacement at enterprise sites or exchange locations reference the specific inventory asset. Required for maintenance scheduling, asse',
    `noc_incident_id` BIGINT COMMENT 'Reference to a ServiceNow ITSM incident record associated with this appointment, if the appointment was triggered by or resulted in a fault management incident. Enables cross-domain traceability between order fulfillment and fault management.',
    `ont_asset_id` BIGINT COMMENT 'Foreign key linking to inventory.ont_asset. Business justification: Fiber installation appointments reference the specific ONT asset to be installed at the customer premises. Technicians need direct ONT asset reference for pre-staging, configuration preparation, and p',
    `ran_cell_id` BIGINT COMMENT 'Foreign key linking to network.ran_cell. Business justification: Field appointments for RAN cell installation, antenna alignment, or cell site maintenance reference the specific cell. Workforce scheduling and dispatch for cell site visits require cell-level appoint',
    `site_id` BIGINT COMMENT 'Foreign key linking to enterprise.site. Business justification: Field appointments for enterprise customers target specific sites. Critical for technician dispatch, site access coordination, site contact management, and tracking installation history per location.',
    `svc_instance_id` BIGINT COMMENT 'Foreign key linking to service.svc_instance. Business justification: A field appointment is scheduled to install, repair, or upgrade a specific service instance. Linking appointment to svc_instance enables field operations to track which service a technician visit addr',
    `team_id` BIGINT COMMENT 'Foreign key linking to workforce.team. Business justification: Complex telecom installations (fiber, enterprise) require crew-based appointments assigned to a team rather than a single technician. Field operations scheduling and team capacity planning require lin',
    `technician_id` BIGINT COMMENT 'Reference to the assigned field technician from the workforce domain. Populated by Granite Telecommunications Workforce Management (WFM) during dispatch scheduling.',
    `transmission_link_id` BIGINT COMMENT 'Foreign key linking to network.transmission_link. Business justification: Field appointments for transmission link installation, fiber splicing, or leased-line commissioning reference the specific link. Technician dispatch and appointment scheduling for fixed-line work requ',
    `trouble_ticket_id` BIGINT COMMENT 'Foreign key linking to assurance.trouble_ticket. Business justification: Field appointments are frequently scheduled to resolve trouble tickets — technician dispatched to fix reported service fault. Telecom field operations require linking appointments to originating troub',
    `access_instructions` STRING COMMENT 'Special instructions for the field technician to gain access to the customer premises (e.g., gate codes, building manager contact, parking instructions, safety requirements). Critical for enterprise and multi-dwelling unit installations.',
    `actual_arrival_time` TIMESTAMP COMMENT 'Actual date and time the field technician arrived at the customer premises. Compared against scheduled_start_time to measure on-time arrival performance and SLA adherence.',
    `actual_completion_time` TIMESTAMP COMMENT 'Actual date and time the field technician completed the on-site work and closed the appointment. Used to calculate job duration, MTTR (Mean Time to Repair), and workforce productivity metrics.',
    `actual_duration_minutes` STRING COMMENT 'Actual time in minutes taken to complete the on-site work, calculated from actual_arrival_time to actual_completion_time. Used for workforce productivity analysis and future duration estimation model training.',
    `appointment_number` STRING COMMENT 'Externally visible, human-readable appointment reference number communicated to the customer and field technician. Follows the format APT-NNNNNNNNNN. Used in customer notifications, WFM dispatch sheets, and trouble ticket references.. Valid values are `^APT-[0-9]{10}$`',
    `appointment_status` STRING COMMENT 'Current lifecycle state of the appointment. Drives downstream workflow actions: SCHEDULED (created, not yet confirmed), CONFIRMED (customer acknowledged), COMPLETED (work done), MISSED (technician or customer no-show), RESCHEDULED (new slot assigned), CANCELLED (appointment voided).. Valid values are `SCHEDULED|CONFIRMED|COMPLETED|MISSED|RESCHEDULED|CANCELLED`',
    `appointment_type` STRING COMMENT 'Classification of the on-site work to be performed. Drives technician skill matching, equipment pre-staging, and estimated duration in WFM. [ENUM-REF-CANDIDATE: FTTH_INSTALLATION|GPON_INSTALLATION|CPE_SWAP|ONT_REPLACEMENT|ENTERPRISE_CIRCUIT_COMMISSIONING|FAULT_REPAIR|UPGRADE|DOWNGRADE|DISCONNECTION — promote to reference product]. Valid values are `FTTH_INSTALLATION|GPON_INSTALLATION|CPE_SWAP|ONT_REPLACEMENT|ENTERPRISE_CIRCUIT_COMMISSIONING|FAULT_REPAIR`',
    `completion_notes` STRING COMMENT 'Free-text notes entered by the field technician upon appointment completion. Captures work performed, issues encountered, materials used, and any follow-up actions required. Populated when appointment_status is COMPLETED.',
    `confirmation_channel` STRING COMMENT 'Channel through which the customer confirmed the appointment. Supports omnichannel analytics and confirmation effectiveness reporting. Populated only when customer_confirmed is True.. Valid values are `SMS|EMAIL|IVR|AGENT|SELF_SERVICE_PORTAL`',
    `confirmation_timestamp` TIMESTAMP COMMENT 'Date and time when the customer confirmed the appointment. Populated only when customer_confirmed is True. Used for lead-time analysis and confirmation workflow SLA measurement.',
    `cpe_serial_number` STRING COMMENT 'Serial number of the specific CPE or ONT unit assigned for installation or replacement. Enables asset tracking, warranty management, and post-installation inventory reconciliation.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the appointment record was first created in the system. Audit trail field aligned with data governance and regulatory record-keeping requirements.',
    `customer_confirmed` BOOLEAN COMMENT 'Indicates whether the customer has explicitly confirmed the scheduled appointment. True = confirmed by customer; False = not yet confirmed. Drives automated reminder workflows and no-show risk scoring.',
    `dispatch_work_order_number` STRING COMMENT 'External work order reference number generated by Granite Telecommunications WFM upon technician dispatch. Used to cross-reference appointment records with WFM dispatch sheets and field activity logs.',
    `estimated_duration_minutes` STRING COMMENT 'Estimated time in minutes required to complete the on-site work. Derived from appointment type and technology type during WFM scheduling. Used for route optimization and technician capacity planning.',
    `follow_up_reason` STRING COMMENT 'Free-text description of why a follow-up appointment or action is required. Populated only when follow_up_required is True. Used for work order creation and technician briefing.',
    `follow_up_required` BOOLEAN COMMENT 'Indicates whether a follow-up appointment or action is required after this appointment. True = follow-up needed (e.g., incomplete installation, pending network provisioning). Triggers creation of a new appointment or trouble ticket.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time when the appointment record was most recently updated. Supports change tracking, audit compliance, and incremental data pipeline processing in the Databricks Silver Layer.',
    `missed_reason` STRING COMMENT 'Reason code explaining why the appointment was missed. Populated only when appointment_status is MISSED. Used for SLA breach analysis, customer compensation workflows, and workforce accountability reporting.. Valid values are `CUSTOMER_NO_SHOW|TECHNICIAN_NO_SHOW|ACCESS_DENIED|SAFETY_CONCERN|OTHER`',
    `priority` STRING COMMENT 'Business priority level assigned to the appointment, influencing scheduling queue position and technician dispatch urgency. CRITICAL is reserved for enterprise SLA-bound circuits and regulatory commitments.. Valid values are `CRITICAL|HIGH|MEDIUM|LOW`',
    `reschedule_count` STRING COMMENT 'Number of times this appointment has been rescheduled. Tracks appointment instability, customer experience impact, and operational efficiency. High reschedule counts may trigger escalation workflows.',
    `reschedule_reason` STRING COMMENT 'Reason code for the most recent reschedule of this appointment. Populated when appointment_status is RESCHEDULED. Used for root cause analysis and operational improvement. [ENUM-REF-CANDIDATE: CUSTOMER_REQUEST|TECHNICIAN_UNAVAILABLE|WEATHER|EQUIPMENT_NOT_READY|ACCESS_ISSUE|NETWORK_DEPENDENCY|OTHER — promote to reference product]',
    `scheduled_date` DATE COMMENT 'Calendar date on which the field technician appointment is scheduled to occur. Used for day-level planning, route optimization, and customer communication.',
    `scheduled_end_time` TIMESTAMP COMMENT 'Precise date and time at which the appointment window is scheduled to end. Defines the committed service window communicated to the customer and used for SLA compliance tracking.',
    `scheduled_start_time` TIMESTAMP COMMENT 'Precise date and time at which the appointment window is scheduled to begin. Used for technician dispatch, customer notification, and SLA (Service Level Agreement) measurement.',
    `service_type` STRING COMMENT 'Classification of the customer service segment for which the appointment is being conducted. Drives SLA tier assignment, technician skill requirements, and regulatory reporting categorization.. Valid values are `RESIDENTIAL|SMALL_BUSINESS|ENTERPRISE|WHOLESALE`',
    `sla_commitment_met` BOOLEAN COMMENT 'Indicates whether the appointment was completed within the committed SLA (Service Level Agreement) window. True = SLA met; False = SLA breached. Drives regulatory reporting, customer compensation, and performance dashboards.',
    `sla_target_date` DATE COMMENT 'The contractual or regulatory deadline by which the appointment must be completed to satisfy the SLA commitment. Derived from order creation date and applicable SLA tier.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this appointment record originated. Supports data lineage, reconciliation, and Silver Layer provenance tracking. Primary source is Granite Telecommunications WFM; secondary sources include Oracle OSM and Salesforce CRM.. Valid values are `GRANITE_WFM|OSM|SALESFORCE_CRM|SERVICENOW|MANUAL`',
    `technology_type` STRING COMMENT 'Network access technology associated with the appointment work. Determines required technician certifications, tools, and equipment. [ENUM-REF-CANDIDATE: FTTH|GPON|FTTB|HFC|DSL|FIXED_WIRELESS|ENTERPRISE_FIBER|5G_FWA — promote to reference product]',
    `wfm_job_reference` STRING COMMENT 'Unique job identifier assigned by Granite Telecommunications Workforce Management system for this appointment. Enables bidirectional traceability between the order domain and the WFM dispatch system.',
    CONSTRAINT pk_appointment PRIMARY KEY(`appointment_id`)
) COMMENT 'Field technician installation or service appointment record associated with a fulfillment order requiring on-site work — FTTH/GPON installation, CPE swap, ONT replacement, or enterprise circuit commissioning. Captures appointment type, scheduled date and time window, customer address, assigned technician reference (linked to workforce domain), appointment status (SCHEDULED, CONFIRMED, COMPLETED, MISSED, RESCHEDULED), customer confirmation flag, and completion notes. Integrates with Granite Telecommunications WFM for dispatch.';

CREATE OR REPLACE TABLE `telecommunication_ecm`.`order`.`sla` (
    `sla_id` BIGINT COMMENT 'Unique surrogate identifier for the order SLA commitment record. Primary key for this entity in the Silver Layer lakehouse.',
    `agreement_id` BIGINT COMMENT 'Foreign key linking to partner.partner_agreement. Business justification: Partner-originated orders may have SLA terms defined in partner agreements rather than standard retail SLAs - required for partner SLA compliance measurement and penalty/credit calculation in telecomm',
    `corporate_account_id` BIGINT COMMENT 'Foreign key linking to enterprise.corporate_account. Business justification: Enterprise SLA performance reporting is aggregated at corporate account level for account management reviews, churn risk assessment, and executive dashboards. Direct link enables account-level SLA bre',
    `enterprise_contract_id` BIGINT COMMENT 'Foreign key linking to enterprise.enterprise_contract. Business justification: Order SLA commitments are governed by enterprise contracts that define SLA tiers, penalty clauses, and breach thresholds. Direct link enables contract-level SLA breach penalty calculation and regulato',
    `fulfillment_order_id` BIGINT COMMENT 'Reference to the fulfillment order to which this SLA commitment is attached. Links the SLA record to its parent order in Oracle Communications Order and Service Management.',
    `noc_incident_id` BIGINT COMMENT 'Foreign key linking to assurance.noc_incident. Business justification: SLA clocks are suspended during NOC-declared network incidents in telecom. order.sla has clock_suspended and suspension_reason fields indicating this scenario. Linking to the noc_incident enables accu',
    `offering_id` BIGINT COMMENT 'Foreign key linking to product.offering. Business justification: Offering-level SLA compliance reporting: SLA commitments and breach rates must be tracked per product offering for regulatory reporting, product quality management, and customer segment SLA dashboards',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Many order SLAs are regulatory-mandated (FCC broadband deployment commitments, EU consumer protection timelines, MNP porting deadlines). Telcos must link SLA definitions to their regulatory source for',
    `sla_definition_id` BIGINT COMMENT 'Foreign key linking to partner.sla_definition. Business justification: Operational SLA records must reference the contractual SLA definition from the partner agreement that governs measurement method, penalty formula, and thresholds. Telecom operators link live SLA insta',
    `sla_profile_id` BIGINT COMMENT 'Foreign key linking to service.sla_profile. Business justification: An order SLA commitment is governed by the service SLA profile tier (e.g., Gold, Platinum) associated with the ordered service. Linking order.sla to service.sla_profile enables SLA compliance reportin',
    `transmission_link_id` BIGINT COMMENT 'Foreign key linking to network.transmission_link. Business justification: Order-level SLAs for leased-line and fixed broadband services are tied to the specific transmission link. SLA measurement, breach detection, and regulatory reporting for fixed-line services require kn',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to workforce.work_order. Business justification: SLA breach root-cause analysis in telecom requires direct linkage between an SLA record and the work order responsible for field execution delays. SLA compliance reporting and penalty calculation depe',
    `actual_completion_timestamp` TIMESTAMP COMMENT 'The actual date and time the measurement_end_event occurred, marking fulfillment of the order. Null if the order has not yet been completed. Used to compute final SLA outcome (met or breached) for regulatory reporting.',
    `breach_notification_sent` BOOLEAN COMMENT 'Indicates whether a formal breach notification has been dispatched to the customer and/or regulatory authority (True) following a BREACHED status. Required for compliance with FCC, Ofcom, and BEREC breach reporting obligations.',
    `breach_notification_timestamp` TIMESTAMP COMMENT 'The date and time at which the breach notification was sent to the customer and/or regulatory authority. Null if no notification has been sent. Used to verify compliance with mandatory notification timeframes.',
    `breach_threshold_hours` DECIMAL(18,2) COMMENT 'The number of elapsed hours from the measurement start event at which the SLA is formally classified as BREACHED. May equal target_completion_hours or include a grace period defined in the contract or regulatory instrument.',
    `breach_timestamp` TIMESTAMP COMMENT 'The exact date and time at which the SLA was formally classified as BREACHED (i.e., elapsed hours exceeded breach_threshold_hours). Null if the SLA has not been breached. Critical for regulatory penalty calculations and breach notification obligations.',
    `calendar_type` STRING COMMENT 'Defines how elapsed time is measured for this SLA: CALENDAR_HOURS (24x7 clock), BUSINESS_HOURS (measured only during defined business operating hours), or BUSINESS_DAYS (measured in working days). Determines how target_completion_timestamp is calculated.. Valid values are `CALENDAR_HOURS|BUSINESS_HOURS|BUSINESS_DAYS`',
    `clock_suspended` BOOLEAN COMMENT 'Indicates whether the SLA measurement clock is currently paused (True) due to a customer hold, third-party dependency, or regulatory exclusion event. When True, elapsed_hours accumulation is halted until the clock is resumed.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time this SLA record was first created in the Silver Layer lakehouse. Serves as the RECORD_AUDIT_CREATED timestamp for data lineage and audit trail purposes.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the penalty_credit_amount (e.g., USD, GBP, EUR). Ensures multi-currency support for international operations.. Valid values are `^[A-Z]{3}$`',
    `customer_segment` STRING COMMENT 'The customer segment to which the order and SLA apply: CONSUMER (residential), SMB (Small and Medium Business), ENTERPRISE (large corporate), WHOLESALE (carrier/partner), or MVNO (Mobile Virtual Network Operator). Determines SLA tier and applicable contractual terms.. Valid values are `CONSUMER|SMB|ENTERPRISE|WHOLESALE|MVNO`',
    `effective_from_date` DATE COMMENT 'The date from which this SLA definition version became effective. Used for SLA versioning and to ensure the correct SLA terms are applied to orders placed within a given period.',
    `effective_until_date` DATE COMMENT 'The date until which this SLA definition version remains effective. Null for open-ended SLA definitions. Used for SLA versioning and regulatory compliance period tracking.',
    `elapsed_hours` DECIMAL(18,2) COMMENT 'The number of hours elapsed since the measurement start event as of the last status evaluation. Used for real-time SLA monitoring dashboards and regulatory compliance reporting. Excludes any suspended clock periods.',
    `escalation_level` STRING COMMENT 'Current escalation tier for this SLA record (e.g., 0 = no escalation, 1 = team lead, 2 = manager, 3 = executive). Incremented automatically by the SLA monitoring engine as thresholds are crossed. Used for NOC and operations reporting.',
    `measurement_end_event` STRING COMMENT 'The business event that stops the SLA clock and marks fulfillment completion. Used to calculate actual elapsed time against the SLA target. [ENUM-REF-CANDIDATE: SERVICE_ACTIVATED|ORDER_COMPLETED|PORT_COMPLETED|FAULT_RESOLVED|CPE_INSTALLED|CUSTOMER_CONFIRMED — promote to reference product]. Valid values are `SERVICE_ACTIVATED|ORDER_COMPLETED|PORT_COMPLETED|FAULT_RESOLVED|CPE_INSTALLED|CUSTOMER_CONFIRMED`',
    `measurement_start_event` STRING COMMENT 'The business event that triggers the start of SLA clock measurement. Defines the precise moment from which target completion hours are counted, per regulatory or contractual terms. [ENUM-REF-CANDIDATE: ORDER_SUBMITTED|ORDER_ACCEPTED|PAYMENT_CONFIRMED|SITE_SURVEY_COMPLETE|PORT_REQUEST_SUBMITTED|TECHNICIAN_DISPATCHED — promote to reference product]. Valid values are `ORDER_SUBMITTED|ORDER_ACCEPTED|PAYMENT_CONFIRMED|SITE_SURVEY_COMPLETE|PORT_REQUEST_SUBMITTED|TECHNICIAN_DISPATCHED`',
    `measurement_start_timestamp` TIMESTAMP COMMENT 'The precise date and time (ISO 8601 with timezone offset) at which the SLA clock started, corresponding to the occurrence of the measurement_start_event. This is the BUSINESS_EVENT_TIMESTAMP for SLA clock initiation.',
    `notes` STRING COMMENT 'Free-text operational notes or comments associated with this SLA record, such as escalation context, customer communication history, or regulatory exception justifications. Intended for NOC and operations team use.',
    `penalty_applicable` BOOLEAN COMMENT 'Indicates whether a financial penalty or service credit is contractually or regulatorily applicable upon breach of this SLA (True). Drives downstream penalty calculation and credit note generation in Amdocs Revenue Management.',
    `penalty_credit_amount` DECIMAL(18,2) COMMENT 'The monetary value of the service credit or penalty payable to the customer upon SLA breach, expressed in the billing currency. Null if penalty_applicable is False or if the breach has not yet been assessed. Feeds into Amdocs Revenue Management credit note generation.',
    `priority_level` STRING COMMENT 'The operational priority assigned to this SLA record, used to drive escalation routing and resource allocation in ServiceNow ITSM and Oracle Communications Order and Service Management. CRITICAL typically applies to regulatory MNP or enterprise SLAs.. Valid values are `CRITICAL|HIGH|MEDIUM|LOW`',
    `reference_number` STRING COMMENT 'Externally-known business identifier for this SLA commitment record, used in regulatory submissions, customer communications, and cross-system reconciliation (e.g., SLA-2024-00123456). Sourced from Oracle Communications Order and Service Management.',
    `regulatory_body` STRING COMMENT 'The regulatory authority whose rules govern this SLA commitment: FCC (Federal Communications Commission, USA), OFCOM (Office of Communications, UK), BEREC (Body of European Regulators for Electronic Communications), ITU (International Telecommunication Union), ETSI, NTIA, GSMA, or NONE for purely commercial SLAs. [ENUM-REF-CANDIDATE: FCC|OFCOM|BEREC|ITU|ETSI|NTIA|GSMA|NONE — 8 candidates stripped; promote to reference product]',
    `regulatory_instrument_reference` STRING COMMENT 'The specific regulatory rule, order, or directive citation that mandates this SLA (e.g., FCC 47 CFR Part 52 Section 52.35, Ofcom General Conditions C5.3, BEREC Guidelines on Switching 2020). Enables precise regulatory compliance traceability.',
    `service_type` STRING COMMENT 'The type of telecommunications service to which this SLA applies: MOBILE, BROADBAND, FIBER_FTTH (Fiber to the Home), VOIP (Voice over Internet Protocol), IPTV (Internet Protocol Television), ENTERPRISE_MPLS (Multiprotocol Label Switching), SD_WAN (Software-Defined Wide Area Network), or FIXED_LINE. Determines applicable SLA regime and regulatory framework. [ENUM-REF-CANDIDATE: MOBILE|BROADBAND|FIBER_FTTH|VOIP|IPTV|ENTERPRISE_MPLS|SD_WAN|FIXED_LINE — promote to reference product]',
    `sla_category` STRING COMMENT 'Functional category of the SLA defining the business process it governs: PROVISIONING (new service activation), REPAIR (fault resolution), PORTABILITY (Mobile Number Portability / MNP), INSTALLATION (physical CPE or FTTH installation), ACTIVATION (service turn-up), or DISCONNECTION (service termination). [ENUM-REF-CANDIDATE: PROVISIONING|REPAIR|PORTABILITY|INSTALLATION|ACTIVATION|DISCONNECTION — promote to reference product if additional categories are required]. Valid values are `PROVISIONING|REPAIR|PORTABILITY|INSTALLATION|ACTIVATION|DISCONNECTION`',
    `sla_status` STRING COMMENT 'Current real-time status of the SLA commitment: ON_TRACK (within target), AT_RISK (warning threshold exceeded), BREACHED (breach threshold exceeded), COMPLETED (fulfilled within SLA), WAIVED (SLA obligation formally waived), or SUSPENDED (clock paused due to customer or third-party hold).. Valid values are `ON_TRACK|AT_RISK|BREACHED|COMPLETED|WAIVED|SUSPENDED`',
    `sla_type` STRING COMMENT 'Classification of the SLA commitment: REGULATORY (mandated by FCC, Ofcom, BEREC, or ITU), COMMERCIAL (contractually agreed with the customer), ENTERPRISE (premium business customer SLA), or INTERNAL (operational target not contractually binding).. Valid values are `REGULATORY|COMMERCIAL|ENTERPRISE|INTERNAL`',
    `source_system` STRING COMMENT 'The operational system of record from which this SLA record originated: ORACLE_OSM (Oracle Communications Order and Service Management), NETCRACKER (Netcracker OSS/BSS Suite), SERVICENOW (ServiceNow ITSM), AMDOCS (Amdocs Revenue Management), or MANUAL (manually entered).. Valid values are `ORACLE_OSM|NETCRACKER|SERVICENOW|AMDOCS|MANUAL`',
    `suspension_reason` STRING COMMENT 'The reason the SLA measurement clock was most recently suspended. Used for regulatory exclusion reporting and dispute resolution. [ENUM-REF-CANDIDATE: CUSTOMER_HOLD|THIRD_PARTY_DEPENDENCY|REGULATORY_EXCLUSION|FORCE_MAJEURE|AWAITING_PAYMENT|SITE_ACCESS_DENIED — promote to reference product]. Valid values are `CUSTOMER_HOLD|THIRD_PARTY_DEPENDENCY|REGULATORY_EXCLUSION|FORCE_MAJEURE|AWAITING_PAYMENT|SITE_ACCESS_DENIED`',
    `target_completion_hours` DECIMAL(18,2) COMMENT 'The contracted or regulatory maximum number of hours within which the order must be fulfilled from the measurement start event. This is the primary SLA commitment value (e.g., 24.00 hours for MNP port-in per FCC rules, 48.00 hours for residential broadband activation).',
    `target_completion_timestamp` TIMESTAMP COMMENT 'The calculated deadline timestamp by which the order must be fulfilled to meet the SLA commitment. Derived from measurement_start_timestamp plus target_completion_hours, adjusted for any calendar or business-hours rules. Stored for direct comparison in monitoring queries.',
    `total_suspended_hours` DECIMAL(18,2) COMMENT 'Cumulative number of hours the SLA clock has been suspended for this record due to customer holds, third-party delays, or regulatory exclusions. Subtracted from gross elapsed time to compute net elapsed hours for compliance reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time this SLA record was last modified in the Silver Layer lakehouse. Serves as the RECORD_AUDIT_UPDATED timestamp for change tracking, incremental processing, and audit trail purposes.',
    `version` STRING COMMENT 'The version identifier of the SLA template or regulatory instrument applied to this record (e.g., v2.1, 2024-Q1). Enables tracking of SLA policy changes over time and ensures correct terms are applied for historical reporting.',
    `waiver_reason` STRING COMMENT 'Free-text description of the reason the SLA obligation was formally waived (e.g., customer-requested delay, force majeure, regulatory exclusion). Populated only when sla_status is WAIVED. Required for audit and regulatory justification.',
    `warning_threshold_hours` DECIMAL(18,2) COMMENT 'The number of elapsed hours from the measurement start event at which the SLA status transitions to AT_RISK, triggering proactive escalation workflows in Oracle Communications Order and Service Management and ServiceNow ITSM. Typically set as a percentage of target_completion_hours (e.g., 75%).',
    `warning_triggered_timestamp` TIMESTAMP COMMENT 'The date and time at which the SLA status transitioned to AT_RISK (warning threshold exceeded). Used to measure the effectiveness of proactive escalation workflows and to audit response times.',
    CONSTRAINT pk_sla PRIMARY KEY(`sla_id`)
) COMMENT 'SLA commitment record attached to a fulfillment order or order type, defining the contracted or regulatory completion timeframe. Captures SLA type (regulatory, commercial, enterprise), target completion hours, warning threshold hours, breach threshold hours, measurement start event, measurement end event, current SLA status (ON_TRACK, AT_RISK, BREACHED), breach timestamp if applicable, and applicable regulatory body (FCC, Ofcom, BEREC). Enables real-time SLA monitoring and regulatory compliance reporting.';

CREATE OR REPLACE TABLE `telecommunication_ecm`.`order`.`notification` (
    `notification_id` BIGINT COMMENT 'Unique surrogate identifier for each outbound order notification record dispatched to a customer or internal stakeholder. Primary key of the order_notification data product.',
    `amendment_id` BIGINT COMMENT 'Foreign key linking to order.amendment. Business justification: Notifications are triggered by post-submission amendments (customer-requested changes, regulatory holds, etc.). The notification table has source_event_reference (STRING) as a loose reference, but a p',
    `appointment_id` BIGINT COMMENT 'Foreign key linking to order.appointment. Business justification: Notifications are dispatched at key order lifecycle events including appointment confirmations, reminders, and reschedule alerts. The notification table currently stores appointment_date and appointme',
    `corporate_account_id` BIGINT COMMENT 'Foreign key linking to enterprise.corporate_account. Business justification: Enterprise order notifications must be routed to corporate account communication preferences, designated contacts, and escalation paths. Direct link enables corporate account notification audit trails',
    `customer_account_id` BIGINT COMMENT 'Reference to the customer who is the primary recipient of this notification. Sourced from Salesforce CRM Customer 360 and used to resolve recipient contact details.',
    `fulfillment_order_id` BIGINT COMMENT 'Reference to the parent order that triggered this notification. Links the notification to the end-to-end order lifecycle managed in Oracle Communications Order and Service Management (OSM).',
    `mnp_transaction_id` BIGINT COMMENT 'Foreign key linking to interconnect.mnp_transaction. Business justification: Regulatory MNP notification tracking: notifications to customers and carriers during porting must be linked to the mnp_transaction for regulatory audit (e.g., OFCOM/FCC porting notification compliance',
    `payment_id` BIGINT COMMENT 'Foreign key linking to billing.payment. Business justification: Payment confirmation and receipt notifications must reference the specific payment transaction. Telecom customer experience operations and payment reconciliation processes require notification-to-paym',
    `privacy_consent_id` BIGINT COMMENT 'Foreign key linking to compliance.privacy_consent. Business justification: Notifications (SMS, email, push) require consent verification under privacy regulations (GDPR Article 6, FCC CPNI rules). Real-world telco notification systems check consent records before dispatching',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: notification.regulatory_notification_flag=true means the notification fulfills a specific regulatory obligation. The existing regulatory_obligation_reference is a denormalized text field; replacing wi',
    `sla_breach_event_id` BIGINT COMMENT 'Foreign key linking to assurance.sla_breach_event. Business justification: Customer notifications are mandated when SLA breaches occur in telecom. Linking notification to sla_breach_event provides the regulatory audit trail proving timely customer notification, supports brea',
    `sla_id` BIGINT COMMENT 'Foreign key linking to order.sla. Business justification: Notifications are dispatched when SLA breach thresholds are crossed (warning notifications, breach notifications, regulatory SLA alerts). The notification table has regulatory_notification_flag and so',
    `subscriber_id` BIGINT COMMENT 'Foreign key linking to customer.subscriber. Business justification: Order notifications (MNP port confirmation, SIM activation alerts, appointment reminders) target a specific subscribers MSISDN. The denormalized service_number field should be replaced by a proper FK',
    `svc_instance_id` BIGINT COMMENT 'Foreign key linking to service.svc_instance. Business justification: Customer notifications (activation confirmation, suspension notice, porting completion) are sent about specific service instances. Linking notification to svc_instance enables per-service communicatio',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to workforce.work_order. Business justification: Customer notifications (e.g., technician en route, installation complete) are directly triggered by work order status events. Telecom CX operations require linking notifications to the triggering ',
    `body_hash` STRING COMMENT 'SHA-256 hash of the rendered notification body content at the time of dispatch. Provides tamper-evident audit evidence of the exact message content sent without storing the full message body (which may contain PII).. Valid values are `^[a-f0-9]{64}$`',
    `cancellation_reason_code` STRING COMMENT 'The reason code for order cancellation included in ORDER_CANCELLATION notifications (e.g., CUSTOMER_REQUEST, CREDIT_FAIL, DUPLICATE_ORDER, FRAUD_DETECTED). Populated only when notification_type is ORDER_CANCELLATION.',
    `consent_reference` STRING COMMENT 'Reference to the customers communication consent record that authorises dispatch of this notification via the selected channel. Required for GDPR Article 6 lawful basis and TCPA compliance for SMS/IVR channels.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this notification record was first created in the order notification system. Audit trail field for data lineage and compliance purposes.',
    `delivered_timestamp` TIMESTAMP COMMENT 'The date and time when delivery confirmation was received from the messaging gateway or carrier, confirming the notification reached the recipient endpoint. Null if delivery has not yet been confirmed or failed.',
    `delivery_channel` STRING COMMENT 'The communication channel used to dispatch this notification to the recipient (e.g., SMS, EMAIL, PUSH notification, IVR automated call, WhatsApp, or POSTAL mail). Determines routing logic and delivery SLA expectations.. Valid values are `SMS|EMAIL|PUSH|IVR|WHATSAPP|POSTAL`',
    `delivery_status` STRING COMMENT 'Current delivery outcome status of the notification as reported by the downstream messaging gateway or carrier. SENT = dispatched to gateway; DELIVERED = confirmed receipt by endpoint; FAILED = gateway rejection; BOUNCED = undeliverable address; PENDING = queued for dispatch.. Valid values are `SENT|DELIVERED|FAILED|BOUNCED|PENDING`',
    `dispatch_timestamp` TIMESTAMP COMMENT 'The precise date and time (ISO 8601 with timezone offset) when the notification was submitted to the messaging gateway or delivery platform. Principal business event timestamp for SLA measurement and regulatory audit.',
    `failed_timestamp` TIMESTAMP COMMENT 'The date and time when a delivery failure or bounce was reported by the messaging gateway. Populated only when delivery_status is FAILED or BOUNCED. Used to trigger retry logic and escalation workflows.',
    `failure_reason_code` STRING COMMENT 'The error or failure reason code returned by the messaging gateway when delivery_status is FAILED or BOUNCED (e.g., INVALID_NUMBER, MAILBOX_FULL, UNSUBSCRIBED, NETWORK_ERROR). Used for root cause analysis and retry strategy.',
    `failure_reason_description` STRING COMMENT 'Human-readable description of the delivery failure reason as returned by the messaging gateway. Complements failure_reason_code with additional context for operations and customer service teams.',
    `fallback_channel` STRING COMMENT 'The alternative delivery channel to be used if the primary delivery_channel fails after exhausting retry attempts (e.g., fall back to SMS if EMAIL bounces). Supports multi-channel notification resilience.. Valid values are `SMS|EMAIL|PUSH|IVR|WHATSAPP|POSTAL`',
    `fallback_triggered` BOOLEAN COMMENT 'Indicates whether the fallback delivery channel was activated for this notification because the primary channel failed. True = fallback was used; False = primary channel was used.',
    `gateway_message_reference` STRING COMMENT 'The unique message identifier assigned by the external messaging gateway or carrier (e.g., SMS aggregator message ID, email SMTP message ID, push notification token). Used for delivery receipt correlation and dispute resolution with gateway providers.',
    `gateway_provider` STRING COMMENT 'The name or identifier of the external messaging gateway or aggregator used to deliver this notification (e.g., Twilio, Syniverse, AWS SNS). Supports vendor performance monitoring and SLA management.',
    `language_code` STRING COMMENT 'The IETF BCP 47 language tag identifying the language in which the notification was rendered (e.g., en-US, fr-FR, es-MX). Supports multilingual customer communication obligations and regulatory requirements.. Valid values are `^[a-z]{2}(-[A-Z]{2})?$`',
    `max_retry_limit` STRING COMMENT 'The maximum number of delivery retry attempts permitted for this notification before it is marked as permanently failed and escalated. Configured per notification_type and delivery_channel in the notification policy.',
    `notification_number` STRING COMMENT 'Externally visible, human-readable business identifier for this notification record (e.g., NTF-0012345678). Used in customer-facing correspondence, audit trails, and regulatory evidence for MNP and disconnection notifications.. Valid values are `^NTF-[0-9]{10}$`',
    `notification_type` STRING COMMENT 'Classifies the business event that triggered this notification. Drives template selection, regulatory logging, and SLA measurement. [ENUM-REF-CANDIDATE: ORDER_CONFIRMATION|APPOINTMENT_REMINDER|PROVISIONING_COMPLETE|PORT_IN_EXECUTION|ORDER_CANCELLATION|DISCONNECTION_NOTICE — promote to reference product]. Valid values are `ORDER_CONFIRMATION|APPOINTMENT_REMINDER|PROVISIONING_COMPLETE|PORT_IN_EXECUTION|ORDER_CANCELLATION|DISCONNECTION_NOTICE`',
    `opt_out_flag` BOOLEAN COMMENT 'Indicates whether the recipient had opted out of this notification type or delivery channel at the time of dispatch. True = opt-out was recorded (notification may have been suppressed or sent as regulatory override). Used for GDPR/TCPA compliance audit.',
    `port_execution_date` DATE COMMENT 'The date on which the MNP port-in or port-out was executed, as communicated in PORT_IN_EXECUTION notifications. Required for regulatory audit under FCC MNP Order 18-122 and GSMA PRD IR.73.',
    `priority` STRING COMMENT 'The dispatch priority assigned to this notification, governing queue position and SLA targets in the messaging gateway. CRITICAL = regulatory/MNP notifications requiring immediate dispatch; HIGH = time-sensitive operational; NORMAL = standard; LOW = informational.. Valid values are `CRITICAL|HIGH|NORMAL|LOW`',
    `provisioning_completion_date` DATE COMMENT 'The date on which service provisioning was completed, as communicated in PROVISIONING_COMPLETE notifications. Sourced from Oracle OSM service fulfillment completion event.',
    `recipient_address` STRING COMMENT 'The actual delivery endpoint used for this notification — phone number (E.164 format for SMS/IVR), email address, push device token, or postal address depending on delivery_channel. Stored as dispatched for audit and re-delivery purposes.',
    `recipient_type` STRING COMMENT 'Classifies whether the notification was dispatched to an external customer, an internal business stakeholder, a customer service agent, or a field technician. Governs data handling and privacy obligations.. Valid values are `CUSTOMER|INTERNAL_STAKEHOLDER|AGENT|FIELD_TECHNICIAN`',
    `regulatory_notification_flag` BOOLEAN COMMENT 'Indicates whether this notification fulfils a mandatory regulatory obligation (e.g., MNP port-in confirmation, service disconnection advance notice). True = regulatory notification; False = operational/informational notification. Used for compliance reporting to FCC, Ofcom, BEREC.',
    `retry_count` STRING COMMENT 'The number of delivery retry attempts made for this notification following an initial FAILED or BOUNCED status. Used to enforce maximum retry policies and trigger escalation to an alternative channel.',
    `scheduled_dispatch_timestamp` TIMESTAMP COMMENT 'The planned date and time at which the notification was scheduled to be dispatched. Compared against dispatch_timestamp to measure scheduling accuracy and identify delayed notifications.',
    `source_event_reference` STRING COMMENT 'The unique event or transaction identifier from the originating source system (OSM, Salesforce, Amdocs) that triggered this notification. Enables end-to-end traceability from the source business event to the dispatched notification.',
    `source_system` STRING COMMENT 'The originating operational system that triggered this notification event (e.g., OSM = Oracle Communications Order and Service Management, SALESFORCE_CRM, AMDOCS, NETCRACKER, COMVERSE). Supports data lineage and cross-system reconciliation.. Valid values are `OSM|SALESFORCE_CRM|AMDOCS|NETCRACKER|COMVERSE`',
    `subject` STRING COMMENT 'The subject line or title of the notification as rendered and dispatched (e.g., email subject line, SMS header, push notification title). Captured for audit, content review, and regulatory evidence.',
    `template_version` STRING COMMENT 'The version identifier of the notification template used at the time of dispatch (e.g., v1.0, v2.3). Enables audit of which template content was sent, supporting regulatory compliance and A/B testing analysis.. Valid values are `^v[0-9]+.[0-9]+$`',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this notification record was last modified (e.g., delivery status updated from SENT to DELIVERED). Audit trail field for change tracking and data lineage.',
    CONSTRAINT pk_notification PRIMARY KEY(`notification_id`)
) COMMENT 'Outbound notification record dispatched to customers or internal stakeholders at key order lifecycle milestones — order confirmation, appointment reminder, provisioning completion, port-in execution, and order cancellation. Captures notification type, delivery channel (SMS, email, push, IVR), recipient reference, dispatch timestamp, delivery status (SENT, DELIVERED, FAILED, BOUNCED), template version, and language code. Supports regulatory notification obligations for MNP and service disconnection.';

CREATE OR REPLACE TABLE `telecommunication_ecm`.`order`.`amendment` (
    `amendment_id` BIGINT COMMENT 'Unique surrogate identifier for each order amendment record in the Telecommunication order management system. Primary key for the order_amendment data product.',
    `audit_id` BIGINT COMMENT 'Foreign key linking to compliance.audit. Business justification: Compliance audits frequently identify order amendments required (e.g., incorrect pricing, unauthorized changes). Linking amendment to the audit that triggered it supports corrective action tracking an',
    `corporate_account_id` BIGINT COMMENT 'Foreign key linking to enterprise.corporate_account. Business justification: Enterprise order amendments require corporate account-level tracking for account management reporting, amendment approval workflows, and contract compliance auditing. Enables amendment frequency analy',
    `customer_account_id` BIGINT COMMENT 'Reference to the customer who requested or is impacted by this order amendment. Supports customer-level audit trails and dispute resolution.',
    `discount_scheme_id` BIGINT COMMENT 'Foreign key linking to enterprise.discount_scheme. Business justification: Contract amendments frequently change the applicable enterprise discount scheme (tier upgrades, renegotiations). Direct link enables discount scheme change audit trail and revenue impact analysis of a',
    `enterprise_contract_id` BIGINT COMMENT 'Foreign key linking to enterprise.enterprise_contract. Business justification: Order amendments for enterprise customers require contract linkage to validate change authorization per contract terms, assess pricing impacts, and trigger contract modification workflows for material',
    `fulfillment_order_id` BIGINT COMMENT 'Reference to the parent fulfillment order that this amendment modifies. Links the amendment to its originating order in Oracle Communications Order and Service Management.',
    `line_id` BIGINT COMMENT 'Reference to the specific order line item affected by this amendment, when the modification is scoped to a single line rather than the entire order header.',
    `managed_service_id` BIGINT COMMENT 'Foreign key linking to enterprise.managed_service. Business justification: Managed service configuration changes are executed via order amendments. Direct link enables managed service change history reporting, change window compliance tracking, and managed service lifecycle ',
    `parent_amendment_id` BIGINT COMMENT 'Self-referencing identifier pointing to a prior amendment that this record supersedes or is derived from. Supports amendment chains where a rejected amendment is resubmitted with corrections.',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: amendment.regulatory_hold_flag indicates amendments placed on hold due to regulatory obligations (e.g., MNP freeze periods, mandated service changes). Linking to the specific regulatory_obligation dri',
    `subscriber_id` BIGINT COMMENT 'Foreign key linking to customer.subscriber. Business justification: Contract amendments (plan changes, ETF waivers, contract extensions) are executed at the subscriber level in telecom. amendment links to customer_account_id but not the specific subscriber, preventing',
    `subscription_id` BIGINT COMMENT 'Foreign key linking to customer.customer_subscription. Business justification: Subscription amendments (addon changes, plan upgrades, auto-renewal modifications) are executed against a specific customer_subscription record. Linking amendment directly to customer_subscription ena',
    `svc_instance_id` BIGINT COMMENT 'Foreign key linking to service.svc_instance. Business justification: An amendment modifies a specific service instance (plan upgrade, feature add/remove, contract extension). Linking amendment to svc_instance enables change management tracking per service, supports cus',
    `transmission_link_id` BIGINT COMMENT 'Foreign key linking to network.transmission_link. Business justification: Amendments to fixed-line service orders (bandwidth upgrades, route changes, SLA tier changes) reference the specific transmission link being amended. Change management and order amendment processing f',
    `work_order_id` BIGINT COMMENT 'Reference to the field work order created or modified as a result of this amendment, when requires_field_visit is True. Links to the workforce management dispatch record in Granite Telecommunications Workforce Management.',
    `amended_field_name` STRING COMMENT 'The logical name of the order attribute that was changed by this amendment (e.g., appointment_date, delivery_address_id, product_offering_code, service_configuration_value). Enables fine-grained change history and audit trail per field.',
    `amendment_number` STRING COMMENT 'Externally visible, human-readable business identifier for this amendment, used in customer communications, agent desktops, and dispute resolution workflows. Format: AMD- followed by 10 digits.. Valid values are `^AMD-[0-9]{10}$`',
    `amendment_status` STRING COMMENT 'Current lifecycle state of the amendment request: PENDING (submitted, awaiting review), APPROVED (authorised by agent or system), REJECTED (denied), APPLIED (successfully propagated to the fulfillment order), WITHDRAWN (retracted by the customer before decision).. Valid values are `PENDING|APPROVED|REJECTED|APPLIED|WITHDRAWN`',
    `amendment_type` STRING COMMENT 'Categorises the nature of the post-submission modification: APPOINTMENT_RESCHEDULE (change of installation/delivery date), PRODUCT_CHANGE (swap of selected product or offering), ADDRESS_CHANGE (new delivery or service address), SERVICE_CONFIG_CHANGE (alteration to service parameters), CONTACT_UPDATE (change of contact details), CANCELLATION_REQUEST (request to cancel the order before completion). [ENUM-REF-CANDIDATE: APPOINTMENT_RESCHEDULE|PRODUCT_CHANGE|ADDRESS_CHANGE|SERVICE_CONFIG_CHANGE|CONTACT_UPDATE|CANCELLATION_REQUEST — promote to reference product]. Valid values are `APPOINTMENT_RESCHEDULE|PRODUCT_CHANGE|ADDRESS_CHANGE|SERVICE_CONFIG_CHANGE|CONTACT_UPDATE|CANCELLATION_REQUEST`',
    `applied_timestamp` TIMESTAMP COMMENT 'Date and time at which the approved amendment was successfully propagated and applied to the underlying fulfillment order in Oracle Communications Order and Service Management. Null until status reaches APPLIED.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time at which the amendment was approved by an authorised agent or automated workflow. Null if the amendment has not yet been approved or was rejected.',
    `audit_trail_reference` STRING COMMENT 'Reference identifier linking this amendment record to the immutable audit log entry in the compliance audit system (e.g., ServiceNow CMDB audit record or enterprise audit repository). Supports regulatory audit and dispute resolution evidence chains.',
    `billing_adjustment_required` BOOLEAN COMMENT 'Indicates whether this amendment triggers a billing adjustment in Amdocs Revenue Management (e.g., pro-rated credit, revised charge). When True, the billing team must process a corresponding adjustment record.',
    `cost_delta` DECIMAL(18,2) COMMENT 'The incremental cost impact of this amendment on the order, expressed as a signed decimal. Positive values indicate an increase in order cost; negative values indicate a reduction. Used for revenue assurance and billing adjustment workflows in Amdocs Revenue Management.',
    `cost_delta_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the cost_delta amount (e.g., USD, GBP, EUR). Ensures multi-currency support for international operations.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this amendment record was first persisted in the Silver Layer lakehouse. Distinct from requested_timestamp which captures the business event time.',
    `customer_notification_timestamp` TIMESTAMP COMMENT 'Date and time at which the customer was notified of the amendment outcome. Null if customer_notified_flag is False. Used for regulatory compliance reporting on customer communication timeliness.',
    `customer_notified_flag` BOOLEAN COMMENT 'Indicates whether the customer has been formally notified of the amendment outcome (approval, rejection, or application). Supports compliance with customer communication obligations and SLA notification requirements.',
    `expiry_date` DATE COMMENT 'The date by which a PENDING amendment must be approved or it will automatically expire and be treated as WITHDRAWN. Enforces amendment processing SLAs and prevents stale pending requests from blocking order fulfillment.',
    `impact_assessment_notes` STRING COMMENT 'Free-text field capturing the agents or systems assessment of the downstream impact of this amendment on network provisioning, billing, scheduling, or third-party dependencies. Used during the approval workflow.',
    `is_customer_initiated` BOOLEAN COMMENT 'Distinguishes amendments initiated by the customer from those initiated internally by agents or automated systems (e.g., error corrections, product availability changes). Supports root-cause analysis of amendment volumes and customer experience reporting.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording the most recent update to this amendment record in the Silver Layer. Used for incremental data pipeline processing and change detection.',
    `mnp_impact_flag` BOOLEAN COMMENT 'Indicates whether this amendment affects a Mobile Number Portability (MNP) port-in or port-out request associated with the parent order. When True, the MNP coordinator must be notified to update the porting window with the donor or recipient operator.',
    `new_committed_delivery_date` DATE COMMENT 'The revised committed delivery or installation date resulting from this amendment, applicable when the amendment type is APPOINTMENT_RESCHEDULE or when sla_reset_flag is True. Null if the amendment does not affect the delivery date.',
    `new_value` DECIMAL(18,2) COMMENT 'The replacement value for the amended field as requested by the customer or agent. Stored as a string to accommodate heterogeneous field types. Becomes the effective value once the amendment status reaches APPLIED.',
    `original_committed_delivery_date` DATE COMMENT 'The committed delivery or installation date that was in effect on the parent order before this amendment was applied. Preserved for SLA impact analysis and dispute resolution.',
    `original_value` DECIMAL(18,2) COMMENT 'The value of the amended field as it existed on the order before this amendment was applied. Stored as a string to accommodate heterogeneous field types (dates, codes, identifiers, free text). Essential for dispute resolution and rollback.',
    `priority` STRING COMMENT 'Business priority assigned to this amendment for processing queue management: CRITICAL (immediate action required, e.g., regulatory or safety), HIGH (same-day processing), MEDIUM (standard SLA), LOW (best-effort). Drives agent workqueue ordering.. Valid values are `CRITICAL|HIGH|MEDIUM|LOW`',
    `reason_code` STRING COMMENT 'Standardised reason code explaining why the amendment was raised: CUSTOMER_REQUEST (voluntary change), AGENT_ERROR_CORRECTION (fix for data entry error), SYSTEM_ERROR (automated correction), PRODUCT_UNAVAILABLE (original product no longer available), ADDRESS_VALIDATION_FAIL (address rejected by validation), SCHEDULING_CONFLICT (appointment slot no longer available). [ENUM-REF-CANDIDATE: CUSTOMER_REQUEST|AGENT_ERROR_CORRECTION|SYSTEM_ERROR|PRODUCT_UNAVAILABLE|ADDRESS_VALIDATION_FAIL|SCHEDULING_CONFLICT — promote to reference product]. Valid values are `CUSTOMER_REQUEST|AGENT_ERROR_CORRECTION|SYSTEM_ERROR|PRODUCT_UNAVAILABLE|ADDRESS_VALIDATION_FAIL|SCHEDULING_CONFLICT`',
    `reason_description` STRING COMMENT 'Free-text narrative providing additional context for the amendment reason beyond the structured reason code. Captured from agent notes or customer-provided comments during the amendment request.',
    `regulatory_hold_flag` BOOLEAN COMMENT 'Indicates whether this amendment is subject to a regulatory hold (e.g., MNP porting window freeze, FCC-mandated processing pause, Ofcom dispute freeze). When True, the amendment cannot be processed until the hold is lifted.',
    `rejected_timestamp` TIMESTAMP COMMENT 'Date and time at which the amendment was rejected. Null if the amendment was not rejected.',
    `rejection_reason_code` STRING COMMENT 'Standardised code indicating why the amendment was rejected: ORDER_ALREADY_FULFILLED, AMENDMENT_WINDOW_EXPIRED, PRODUCT_NOT_ELIGIBLE, CREDIT_CHECK_FAILED, DUPLICATE_REQUEST, POLICY_VIOLATION. Null when amendment is not in REJECTED status. [ENUM-REF-CANDIDATE: ORDER_ALREADY_FULFILLED|AMENDMENT_WINDOW_EXPIRED|PRODUCT_NOT_ELIGIBLE|CREDIT_CHECK_FAILED|DUPLICATE_REQUEST|POLICY_VIOLATION — promote to reference product]. Valid values are `ORDER_ALREADY_FULFILLED|AMENDMENT_WINDOW_EXPIRED|PRODUCT_NOT_ELIGIBLE|CREDIT_CHECK_FAILED|DUPLICATE_REQUEST|POLICY_VIOLATION`',
    `rejection_reason_description` STRING COMMENT 'Free-text explanation of why the amendment was rejected, provided by the approving agent or automated decision system. Null when amendment is not in REJECTED status.',
    `requested_timestamp` TIMESTAMP COMMENT 'The exact date and time at which the customer or agent submitted the amendment request. This is the principal business event timestamp for the amendment lifecycle and is used for SLA measurement and audit.',
    `requesting_channel` STRING COMMENT 'The customer interaction channel through which the amendment request was submitted: IVR (Interactive Voice Response), AGENT_ASSISTED (call centre), SELF_SERVICE_WEB, SELF_SERVICE_APP, RETAIL_STORE, CHAT, EMAIL. [ENUM-REF-CANDIDATE: IVR|AGENT_ASSISTED|SELF_SERVICE_WEB|SELF_SERVICE_APP|RETAIL_STORE|CHAT|EMAIL — promote to reference product]',
    `requires_field_visit` BOOLEAN COMMENT 'Indicates whether this amendment necessitates a new or rescheduled field technician visit (e.g., address change for FTTH installation). Triggers workforce management dispatch in Granite Telecommunications Workforce Management when True.',
    `servicenow_change_request_reference` STRING COMMENT 'The ServiceNow ITSM Change Request identifier raised to govern the technical configuration changes required to fulfil this amendment. Format: CHG followed by 7 digits. Null if no ITSM change request was required.. Valid values are `^CHG[0-9]{7}$`',
    `sla_reset_flag` BOOLEAN COMMENT 'Indicates whether applying this amendment resets the SLA clock on the parent order. True when the amendment materially changes the fulfillment scope (e.g., address change, product swap) and the committed delivery date must be recalculated. Critical for SLA compliance reporting.',
    `source_system` STRING COMMENT 'Identifies the originating operational system that submitted this amendment: OMS (Oracle Communications Order and Service Management), CRM (Salesforce CRM), SELF_SERVICE (customer portal or app), IVR, RETAIL_POS, BATCH (automated batch correction). Used for lineage and root-cause analysis.. Valid values are `OMS|CRM|SELF_SERVICE|IVR|RETAIL_POS|BATCH`',
    `source_system_amendment_ref` STRING COMMENT 'The native amendment or change-request identifier from the originating source system (e.g., Oracle OMS internal amendment ID, Salesforce case number). Enables cross-system traceability and reconciliation.',
    `version` STRING COMMENT 'Sequential version counter for amendments on the same order, starting at 1. Enables ordering of the complete change history and identification of the latest amendment state for a given order.',
    CONSTRAINT pk_amendment PRIMARY KEY(`amendment_id`)
) COMMENT 'Record of every post-submission modification to a fulfillment order — customer-requested changes to appointment date, product selection, delivery address, or service configuration before order completion. Captures amendment type, amendment request timestamp, original value, new value, amendment status (PENDING, APPROVED, REJECTED, APPLIED), approving agent reference, and impact assessment (SLA reset flag, cost delta). Maintains a complete change history for dispute resolution and audit.';

CREATE OR REPLACE TABLE `telecommunication_ecm`.`order`.`order_charge` (
    `order_charge_id` BIGINT COMMENT 'Unique identifier for the order charge record. Primary key.',
    `addon_id` BIGINT COMMENT 'Foreign key linking to product.addon. Business justification: Add-on charge billing: when billing for an add-on (e.g., roaming day pass, extra SMS bundle), the order_charge must reference the specific addon for revenue recognition by add-on type, GL account mapp',
    `address_id` BIGINT COMMENT 'Reference to the physical location where the service is delivered. Used for installation charges, equipment delivery fees, and location-based taxation. Null for non-location-specific charges.',
    `amendment_id` BIGINT COMMENT 'Foreign key linking to order.amendment. Business justification: Order charges can be generated as a direct result of amendments — e.g., early termination fees triggered by a downgrade amendment, change-of-service fees, or billing adjustments. The amendment table h',
    `billing_account_id` BIGINT COMMENT 'Reference to the billing account that will be invoiced for this charge. Links the charge to the customer financial account for payment collection.',
    `billing_dispute_id` BIGINT COMMENT 'Reference to the customer dispute case if this charge is under investigation. Null if charge is not disputed. Links to dispute management system for resolution tracking.',
    `corporate_account_id` BIGINT COMMENT 'Foreign key linking to enterprise.corporate_account. Business justification: Enterprise order charges must be attributed to corporate accounts for consolidated billing, revenue recognition by account, and discount scheme application. Enables corporate account revenue reporting',
    `cpe_asset_id` BIGINT COMMENT 'Foreign key linking to inventory.cpe_asset. Business justification: Order charges for CPE equipment (purchase, rental, installation) reference the specific asset being billed. cpe_serial_number on order_charge is a denormalization of the asset reference. Direct FK ena',
    `discount_scheme_id` BIGINT COMMENT 'Foreign key linking to enterprise.discount_scheme. Business justification: Enterprise discount schemes are applied to order charges; the applied scheme must be traceable for discount audit, revenue leakage detection, and scheme performance reporting. promotion_code is a deno',
    `enterprise_contract_id` BIGINT COMMENT 'Foreign key linking to enterprise.enterprise_contract. Business justification: Order charges for enterprise customers must link to contracts for pricing validation, discount application per contract terms, revenue recognition rules, and contract-specific billing arrangements.',
    `fulfillment_order_id` BIGINT COMMENT 'Reference to the parent order that generated this charge. Links the charge to the originating service order.',
    `invoice_id` BIGINT COMMENT 'Reference to the invoice that includes this charge. Null if charge has not yet been invoiced. Enables reconciliation between order charges and billing invoices.',
    `technician_id` BIGINT COMMENT 'Foreign key linking to workforce.technician. Business justification: Telecom billing includes labor charges (truck roll, installation fees) attributable to a specific technician. Labor cost reconciliation and technician billing productivity reports require linking orde',
    `line_id` BIGINT COMMENT 'Reference to the specific order line item that triggered this charge. Enables traceability to the product or service being charged.',
    `managed_service_id` BIGINT COMMENT 'Foreign key linking to enterprise.managed_service. Business justification: Order charges for managed service provisioning, changes, or decommissioning must be linked to the managed service for total cost of ownership reporting and managed service P&L analysis — standard in e',
    `offering_id` BIGINT COMMENT 'Foreign key linking to product.offering. Business justification: Offering-level revenue reporting: finance and product teams require charges attributed directly to product offerings for P&L analysis, offering profitability, and revenue assurance. product_offering_c',
    `payment_arrangement_id` BIGINT COMMENT 'Foreign key linking to billing.payment_arrangement. Business justification: Device installment charges and deferred payment charges are part of payment arrangements. Telecom order-to-cash operations require linking order charges to payment arrangements for installment schedul',
    `price_plan_id` BIGINT COMMENT 'Foreign key linking to product.price_plan. Business justification: Charges originate from catalog price plans; linkage required for revenue assurance audits, charge validation, and GL account mapping. Essential for financial controls and regulatory reporting.',
    `promo_offer_id` BIGINT COMMENT 'Foreign key linking to product.promo_offer. Business justification: Promotional charges must link to catalog promo_offer for campaign ROI tracking, budget consumption monitoring, redemption limit enforcement, and finance reconciliation. Required for marketing analytic',
    `rate_id` BIGINT COMMENT 'Foreign key linking to interconnect.rate. Business justification: Interconnect cost allocation and revenue assurance: order charges for international calls, roaming pass-through, and MNP settlement must reference the interconnect rate applied. Enables margin analysi',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Certain order charges are mandated by regulatory obligations (universal service fund levies, regulatory fees, interconnect charges). Linking order_charge to the governing regulatory_obligation support',
    `revenue_share_plan_id` BIGINT COMMENT 'Foreign key linking to partner.revenue_share_plan. Business justification: Order charges for dealer/partner-originated sales are subject to revenue share calculations. The revenue share plan governs commission percentage owed to the partner per charge. Telecom operators link',
    `sla_breach_event_id` BIGINT COMMENT 'Foreign key linking to assurance.sla_breach_event. Business justification: SLA breach events in telecom trigger penalty credits recorded as order charges. Linking order_charge to sla_breach_event provides the audit trail required for regulatory reporting, billing dispute res',
    `spec_id` BIGINT COMMENT 'Reference to the product catalog entry associated with this charge. Identifies the specific service or equipment being charged.',
    `svc_instance_id` BIGINT COMMENT 'Foreign key linking to service.svc_instance. Business justification: Order charges (activation fees, installation fees, early termination fees) are levied against a specific service instance. Linking order_charge to svc_instance enables per-service revenue recognition,',
    `transmission_link_id` BIGINT COMMENT 'Foreign key linking to network.transmission_link. Business justification: One-time installation charges and recurring rental charges for transmission link services are associated with the specific link. Revenue recognition, billing reconciliation, and charge audit for fixed',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to workforce.work_order. Business justification: Work orders generate material and labor costs that are billed as order charges (installation fees, equipment delivery). Telecom cost-to-revenue reconciliation and work order profitability reporting re',
    `amount` DECIMAL(18,2) COMMENT 'Gross monetary value of the charge before taxes, discounts, or adjustments. Represents the base price for the service or product being charged.',
    `approval_timestamp` TIMESTAMP COMMENT 'Timestamp when the charge was approved for billing. Null if charge is still pending approval or was waived/cancelled before approval.',
    `billed_timestamp` TIMESTAMP COMMENT 'Timestamp when the charge was successfully posted to a customer invoice. Null if charge has not yet been billed or was waived/cancelled.',
    `channel_code` STRING COMMENT 'Sales channel through which the order was placed. RETAIL_STORE for physical locations, ONLINE_WEB for website orders, MOBILE_APP for mobile application, CALL_CENTER for phone orders, DEALER for authorized resellers, PARTNER for co-branded channels, DIRECT_SALES for field sales teams, TELESALES for outbound sales. [ENUM-REF-CANDIDATE: RETAIL_STORE|ONLINE_WEB|MOBILE_APP|CALL_CENTER|DEALER|PARTNER|DIRECT_SALES|TELESALES — 8 candidates stripped; promote to reference product]',
    `charge_category` STRING COMMENT 'Detailed classification of the charge purpose. ACTIVATION for new service setup, INSTALLATION for field technician deployment, CPE_PURCHASE for customer premises equipment sale, CPE_RENTAL for equipment lease, MNP_FEE for mobile number portability administrative charge, EARLY_TERMINATION for contract breach penalty, SERVICE_CHANGE for mid-contract modifications, UPGRADE/DOWNGRADE for plan changes, DISCONNECTION for service termination, ADMINISTRATIVE for processing fees. [ENUM-REF-CANDIDATE: ACTIVATION|INSTALLATION|CPE_PURCHASE|CPE_RENTAL|MNP_FEE|EARLY_TERMINATION|SERVICE_CHANGE|UPGRADE|DOWNGRADE|DISCONNECTION|ADMINISTRATIVE — 11 candidates stripped; promote to reference product]',
    `charge_status` STRING COMMENT 'Current lifecycle state of the charge. PENDING awaiting approval or billing system processing, APPROVED validated and ready for invoicing, BILLED successfully included in customer invoice, WAIVED forgiven per policy or customer service decision, REVERSED cancelled post-billing with credit issued, DISPUTED under customer challenge investigation, CANCELLED voided before billing. [ENUM-REF-CANDIDATE: PENDING|APPROVED|BILLED|WAIVED|REVERSED|DISPUTED|CANCELLED — 7 candidates stripped; promote to reference product]',
    `charge_type` STRING COMMENT 'Classification of the charge based on billing frequency and nature. ONE_TIME for activation/installation fees, RECURRING for subscription charges, USAGE for consumption-based charges, PENALTY for early termination or late payment fees, ADJUSTMENT for manual corrections, CREDIT for refunds or promotional credits.. Valid values are `ONE_TIME|RECURRING|USAGE|PENALTY|ADJUSTMENT|CREDIT`',
    `contract_term_months` STRING COMMENT 'Duration of the service contract commitment in months. Used to calculate early termination fees and contract expiration dates. Null for month-to-month services.',
    `creation_timestamp` TIMESTAMP COMMENT 'System timestamp when this charge record was first created in the order management system. Used for audit trail and charge lifecycle tracking.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for all monetary amounts in this charge record. Examples: USD, EUR, GBP, JPY, AUD.. Valid values are `^[A-Z]{3}$`',
    `discount_amount` DECIMAL(18,2) COMMENT 'Total discount applied to the charge. Includes promotional discounts, loyalty credits, bundle savings, and negotiated contract reductions.',
    `effective_date` DATE COMMENT 'Date when the charge becomes applicable for billing purposes. Determines which billing cycle will include this charge.',
    `external_charge_reference` STRING COMMENT 'Charge identifier from the source operational system. Used for cross-system reconciliation and data lineage tracking. Format varies by source system.',
    `gl_account_code` STRING COMMENT 'Financial accounting code for revenue recognition. Maps the charge to the appropriate general ledger account for financial reporting and compliance.. Valid values are `^[0-9]{4,10}$`',
    `is_prorated` BOOLEAN COMMENT 'Indicates whether the charge amount was prorated based on partial billing period. True for mid-cycle activations or changes, False for full-period charges.',
    `last_modified_by` STRING COMMENT 'User ID or system identifier that performed the most recent update to this charge record. Used for audit trail and accountability.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this charge record. Used for change tracking, audit trail, and data synchronization.',
    `net_charge_amount` DECIMAL(18,2) COMMENT 'Final billable amount after applying discounts and adding taxes. Calculated as charge_amount minus discount_amount plus tax_amount. This is the amount that will appear on the customer invoice.',
    `proration_days` STRING COMMENT 'Number of days used to calculate prorated charge amount. Null if charge is not prorated.',
    `reference_number` STRING COMMENT 'Externally visible unique business identifier for the charge. Used for customer communication, dispute resolution, and cross-system reconciliation.. Valid values are `^CHG-[0-9]{10}$`',
    `revenue_recognition_date` DATE COMMENT 'Date when revenue from this charge should be recognized in financial statements. May differ from charge_effective_date based on accounting policies and revenue recognition standards.',
    `reversal_description` STRING COMMENT 'Free-text explanation providing additional context for the charge reversal. Includes investigation findings, customer communication notes, or corrective action details. Null if charge was not reversed.',
    `reversal_reason_code` STRING COMMENT 'Standardized code explaining why a previously billed charge was reversed. BILLING_ERROR for incorrect invoicing, DUPLICATE_CHARGE for double-billing, SERVICE_NOT_DELIVERED for unfulfilled orders, CUSTOMER_DISPUTE for contested charges, SYSTEM_ERROR for technical failures, FRAUD for unauthorized charges, REGULATORY_ADJUSTMENT for compliance corrections. Null if charge was not reversed. [ENUM-REF-CANDIDATE: BILLING_ERROR|DUPLICATE_CHARGE|SERVICE_NOT_DELIVERED|CUSTOMER_DISPUTE|SYSTEM_ERROR|FRAUD|REGULATORY_ADJUSTMENT — 7 candidates stripped; promote to reference product]',
    `reversal_timestamp` TIMESTAMP COMMENT 'Timestamp when the charge reversal was processed. Null if charge was not reversed. Used for financial reconciliation and audit trail.',
    `source_system_code` STRING COMMENT 'Identifier of the operational system that originated this charge record. OSM for Oracle Communications Order and Service Management, NETCRACKER for Netcracker OSS/BSS Suite, AMDOCS for Amdocs Revenue Management, COMVERSE for Comverse ONE, SALESFORCE for Salesforce CRM. Used for data lineage and system integration troubleshooting.. Valid values are `OSM|NETCRACKER|AMDOCS|COMVERSE|SALESFORCE`',
    `tax_amount` DECIMAL(18,2) COMMENT 'Total tax liability for this charge. Includes sales tax, value-added tax (VAT), goods and services tax (GST), telecommunications-specific regulatory fees, and universal service fund contributions.',
    `tax_category` STRING COMMENT 'Tax treatment classification for this charge. STANDARD for normal sales tax rate, REDUCED for discounted rate items, EXEMPT for non-taxable services, ZERO_RATED for taxable but 0% rate, TELECOM_SPECIFIC for industry regulatory fees, USF for Universal Service Fund contributions.. Valid values are `STANDARD|REDUCED|EXEMPT|ZERO_RATED|TELECOM_SPECIFIC|USF`',
    `trigger_event` STRING COMMENT 'Business event that caused this charge to be generated. ORDER_COMPLETION for order fulfillment charges, SERVICE_ACTIVATION for go-live fees, INSTALLATION_COMPLETE for field work charges, CONTRACT_SIGNATURE for commitment fees, MNP_PORT_IN for number portability administrative charges, SERVICE_DISCONNECTION for termination fees, CONTRACT_TERMINATION for early exit penalties, PLAN_CHANGE for modification fees, EQUIPMENT_DELIVERY for CPE charges. [ENUM-REF-CANDIDATE: ORDER_COMPLETION|SERVICE_ACTIVATION|INSTALLATION_COMPLETE|CONTRACT_SIGNATURE|MNP_PORT_IN|SERVICE_DISCONNECTION|CONTRACT_TERMINATION|PLAN_CHANGE|EQUIPMENT_DELIVERY — 9 candidates stripped; promote to reference product]',
    `waiver_approved_by` STRING COMMENT 'User ID or name of the employee who authorized the charge waiver. Used for audit trail and policy compliance verification. Null if charge was not waived.',
    `waiver_description` STRING COMMENT 'Free-text explanation providing additional context for the charge waiver. Includes customer service notes, manager approval justification, or policy reference. Null if charge was not waived.',
    `waiver_reason_code` STRING COMMENT 'Standardized code explaining why a charge was waived. CUSTOMER_RETENTION for churn prevention, SERVICE_FAILURE for quality issues, BILLING_ERROR for system mistakes, PROMOTIONAL for marketing campaigns, GOODWILL for customer satisfaction, EXECUTIVE_ESCALATION for senior management decisions, REGULATORY_COMPLIANCE for legal requirements, CONTRACT_NEGOTIATION for commercial agreements. Null if charge was not waived. [ENUM-REF-CANDIDATE: CUSTOMER_RETENTION|SERVICE_FAILURE|BILLING_ERROR|PROMOTIONAL|GOODWILL|EXECUTIVE_ESCALATION|REGULATORY_COMPLIANCE|CONTRACT_NEGOTIATION — 8 candidates stripped; promote to reference product]',
    CONSTRAINT pk_order_charge PRIMARY KEY(`order_charge_id`)
) COMMENT 'One-time or recurring charge record generated at order completion and passed to the billing domain for invoicing — activation fees, installation charges, CPE purchase or rental fees, early termination fees, and MNP administrative charges. Captures charge type, charge amount, currency, tax category, charge trigger event, billing account reference, charge status (PENDING, BILLED, WAIVED, REVERSED), and waiver reason if applicable. Represents the commercial financial output of the order fulfillment process.';

